import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import './LeaderboardPreview.css';

export default function LeaderboardPreview() {
    const [topUsers, setTopUsers] = useState([]);
    const [loading, setLoading] = useState(true);
    const navigate = useNavigate();

    useEffect(() => {
        loadTopUsers();
    }, []);

    const loadTopUsers = async () => {
        const { data } = await supabase
            .from('leaderboard_most_wanted')
            .select('*')
            .limit(3);

        setTopUsers(data || []);
        setLoading(false);
    };

    if (loading || topUsers.length === 0) return null;

    return (
        <div className="leaderboard-preview-container" onClick={() => navigate('/leaderboard')}>
            <div className="preview-header">
                <h3>🔥 Campus Stars</h3>
                <span className="view-all">View All →</span>
            </div>

            <div className="preview-list">
                {topUsers.map((user, index) => (
                    <div key={user.id} className="preview-user">
                        <div className="rank-badge">{index + 1}</div>
                        <img src={user.avatar_url || 'https://via.placeholder.com/40'} alt={user.full_name} />
                        <span className="user-name">{user.full_name?.split(' ')[0]}</span>
                    </div>
                ))}
            </div>

            <p className="preview-footer">
                Join the elite. Increase your visibility score!
            </p>
        </div>
    );
}

import { motion, AnimatePresence } from 'framer-motion';
import { useEffect } from 'react';
import './MatchCelebration.css';

export default function MatchCelebration({ isOpen, onClose, userProfile, matchedProfile, onMessage }) {
    useEffect(() => {
        if (isOpen && window.confetti) {
            // Trigger confetti
            const duration = 3 * 1000;
            const animationEnd = Date.now() + duration;
            const defaults = { startVelocity: 30, spread: 360, ticks: 60, zIndex: 9999 };

            const randomInRange = (min, max) => Math.random() * (max - min) + min;

            const interval = setInterval(() => {
                const timeLeft = animationEnd - Date.now();

                if (timeLeft <= 0) {
                    return clearInterval(interval);
                }

                const particleCount = 50 * (timeLeft / duration);
                window.confetti({ ...defaults, particleCount, origin: { x: randomInRange(0.1, 0.3), y: Math.random() - 0.2 } });
                window.confetti({ ...defaults, particleCount, origin: { x: randomInRange(0.7, 0.9), y: Math.random() - 0.2 } });
            }, 250);

            // Haptic vibration (if supported)
            if ('vibrate' in navigator) {
                navigator.vibrate([100, 50, 100]);
            }
        }
    }, [isOpen]);

    return (
        <AnimatePresence>
            {isOpen && (
                <motion.div
                    className="match-celebration-overlay"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                >
                    <div className="match-glass-panel">
                        <motion.div
                            className="match-title-container"
                            initial={{ y: -50, opacity: 0 }}
                            animate={{ y: 0, opacity: 1 }}
                            transition={{ delay: 0.2 }}
                        >
                            <h1 className="match-title-text">It's a Match! 🔥</h1>
                            <p className="match-subtitle">You and {matchedProfile?.full_name} liked each other</p>
                        </motion.div>

                        <div className="match-avatars-merge">
                            <motion.div
                                className="celebration-avatar user-left"
                                initial={{ x: -100, opacity: 0, scale: 0.5 }}
                                animate={{ x: 20, opacity: 1, scale: 1 }}
                                transition={{ type: "spring", stiffness: 100, delay: 0.4 }}
                            >
                                <img src={userProfile?.avatar_url || '/default-avatar.png'} alt="You" />
                            </motion.div>

                            <motion.div
                                className="celebration-avatar user-right"
                                initial={{ x: 100, opacity: 0, scale: 0.5 }}
                                animate={{ x: -20, opacity: 1, scale: 1 }}
                                transition={{ type: "spring", stiffness: 100, delay: 0.4 }}
                            >
                                <img src={matchedProfile?.avatar_url || '/default-avatar.png'} alt="Match" />
                            </motion.div>

                            <motion.div
                                className="match-heart-pulse"
                                initial={{ scale: 0, opacity: 0 }}
                                animate={{ scale: 1.5, opacity: [0, 1, 0] }}
                                transition={{ delay: 0.8, duration: 1, repeat: Infinity }}
                            >
                                ❤️
                            </motion.div>
                        </div>

                        <motion.div
                            className="match-actions-vertical"
                            initial={{ y: 50, opacity: 0 }}
                            animate={{ y: 0, opacity: 1 }}
                            transition={{ delay: 1 }}
                        >
                            <button className="btn-match-message" onClick={onMessage}>
                                Send a Message
                            </button>
                            <button className="btn-match-continue" onClick={onClose}>
                                Keep Swiping
                            </button>
                        </motion.div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    );
}

