import { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { supabase } from '../lib/supabase';
import { getWallet } from '../services/paymentService';
import FeatureCard from '../components/FeatureCard';
import AnalyticsDashboard from '../components/AnalyticsDashboard';
import ViewerTeaser from '../components/ViewerTeaser'; // NEW
import AndroidInstallButton from '../components/AndroidInstallButton';
import './Dashboard.css';

export default function Dashboard() {
    const { currentUser, userProfile } = useAuth();

    const [stats, setStats] = useState({
        matches: 0,
        messages: 0,
        balance: 0,
        pendingBalance: 0,
        totalEarned: 0,
        freeSwipes: 0,
        giftsReceived: 0,
        viewerCount: 0 // Track viewers
    });

    useEffect(() => {
        if (currentUser) {
            fetchStats();
        }
    }, [currentUser]);

    async function fetchStats() {
        try {
            // ... (rest of the fetch logic is already updated in previous turn, fixing duplicate here)
            // Count Matches
            const { count: matchCount } = await supabase
                .from('matches')
                .select('*', { count: 'exact', head: true })
                .or(`user1_id.eq.${currentUser.id},user2_id.eq.${currentUser.id}`);

            // Count Messages (Sent by user)
            const { count: msgCount } = await supabase
                .from('messages')
                .select('*', { count: 'exact', head: true })
                .eq('sender_id', currentUser.id);

            // Get Wallet Detailed Info
            const { data: wallet } = await supabase
                .from('wallets')
                .select('*')
                .eq('user_id', currentUser.id)
                .single();

            // Count Gifts Received
            const { count: giftCount } = await supabase
                .from('wallet_transactions')
                .select('*', { count: 'exact', head: true })
                .eq('user_id', currentUser.id)
                .eq('type', 'gift_received');

            // Count Profile Views (Last 24h)
            const twentyFourHoursAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
            const { count: viewCount } = await supabase
                .from('profile_views')
                .select('*', { count: 'exact', head: true })
                .eq('profile_owner_id', currentUser.id)
                .gt('created_at', twentyFourHoursAgo);

            setStats({
                matches: matchCount || 0,
                messages: msgCount || 0,
                balance: wallet?.available_balance || 0,
                pendingBalance: wallet?.pending_balance || 0,
                totalEarned: wallet?.total_earned || 0,
                freeSwipes: userProfile?.free_swipes || 0,
                giftsReceived: giftCount || 0,
                viewerCount: viewCount || 0
            });
        } catch (err) {
            console.error('Error fetching dashboard stats:', err);
        }
    }

    const displayName = userProfile?.full_name
        || userProfile?.username
        || currentUser?.email?.split('@')[0]
        || 'there';

    const greeting = getGreeting();

    return (
        <div className="dashboard">
            {/* Hero Section */}
            <section className="dashboard-hero">
                <div className="dashboard-hero-content">
                    <h1 className="dashboard-greeting">
                        {greeting}, <span className="dashboard-name">{displayName}</span> 👋
                    </h1>
                    <p className="dashboard-tagline">Ready to find your campus match?</p>
                    <AndroidInstallButton />
                </div>

                {/* Who Viewed You Teaser (Social Proof/Curiosity) */}
                <ViewerTeaser count={stats.viewerCount} />

                <div className="dashboard-stats">
                    {userProfile?.role === 'Male' ? (
                        <>
                            <div className="stat-card clickable" onClick={() => window.location.href = '/wallet'}>
                                <span className="stat-value">₦{stats.balance.toLocaleString()}</span>
                                <span className="stat-label">Balance</span>
                            </div>
                            <div className="stat-card">
                                <span className="stat-value">{stats.freeSwipes}</span>
                                <span className="stat-label">Free Swipes</span>
                            </div>
                        </>
                    ) : (
                        <>
                            <div className="stat-card clickable" onClick={() => window.location.href = '/wallet'}>
                                <span className="stat-value">₦{stats.balance.toLocaleString()}</span>
                                <span className="stat-label">Earnings</span>
                            </div>
                            <div className="stat-card">
                                <span className="stat-value">₦{stats.pendingBalance.toLocaleString()}</span>
                                <span className="stat-label">Pending</span>
                            </div>
                            <div className="stat-card">
                                <span className="stat-value">{stats.giftsReceived}</span>
                                <span className="stat-label">Gifts</span>
                            </div>
                        </>
                    )}
                    <div className="stat-card">
                        <span className="stat-value">{stats.matches}</span>
                        <span className="stat-label">Matches</span>
                    </div>
                </div>
            </section>

            {/* Analytics for Ladies */}
            {userProfile?.role === 'Female' && (
                <AnalyticsDashboard userId={currentUser.id} />
            )}

            {/* Features Grid */}
            <section className="dashboard-features">
                <h2 className="section-title">Explore</h2>
                <div className="features-grid">
                    <FeatureCard
                        icon="💖"
                        title="Discover"
                        description="Swipe and find people you vibe with"
                        to="/discover"
                    />
                    <FeatureCard
                        icon="💬"
                        title="Chat"
                        description="Talk with your matches"
                        to="/chat"
                    />
                    <FeatureCard
                        icon="👤"
                        title="Profile"
                        description="Edit your profile and preferences"
                        to="/profile"
                    />
                </div>
            </section>
        </div>
    );
}

function getGreeting() {
    const hour = new Date().getHours();
    if (hour < 12) return 'Good morning';
    if (hour < 17) return 'Good afternoon';
    return 'Good evening';
}

import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { getDiscoverProfiles, recordSwipe, trackProfileView, checkSwipeLimit, superSwipe } from '../services/swipeService';
import { updatePresence } from '../services/profileService';
import { supabase } from '../lib/supabase';
import { getActiveBoosts } from '../services/paymentService';
import SwipeCard from '../components/SwipeCard';
import LoadingSpinner from '../components/LoadingSpinner';
import StatusBubbles from '../components/StatusBubbles';
import LeaderboardPreview from '../components/LeaderboardPreview';
import MatchCelebration from '../components/MatchCelebration'; // NEW
import StreakIndicator from '../components/StreakIndicator'; // NEW
import { useToast } from '../components/Toast';
import './Discover.css';

export default function Discover() {
    const { currentUser, userProfile } = useAuth();
    const { addToast } = useToast();
    const navigate = useNavigate();

    const [profiles, setProfiles] = useState([]);
    const [loading, setLoading] = useState(true);
    const [matchData, setMatchData] = useState(null); // Updated state for celebration
    const [showFilters, setShowFilters] = useState(false);
    const [showInfo, setShowInfo] = useState(false);
    const [superSwipesAvailable, setSuperSwipesAvailable] = useState(0);
    const [userStreak, setUserStreak] = useState(0); // For Streak System
    const [freeSwipes, setFreeSwipes] = useState(20); // Default to 20, synced in loadProfiles
    const [swipeCount, setSwipeCount] = useState(0); // For Nudge A
    const [showNudge, setShowNudge] = useState(false); // For popup
    const [liveOnly, setLiveOnly] = useState(false);
    const [filters, setFilters] = useState({
        gender: 'All',
        university: 'All',
        ageRange: [18, 50]
    });

    // Limit Reached State
    const [limitReached, setLimitReached] = useState(null);
    const [timeLeft, setTimeLeft] = useState('');

    useEffect(() => {
        loadProfiles(true); // Reset load on filter change
        loadBoosts();
        if (userProfile) setFreeSwipes(userProfile.free_swipes);
    }, [currentUser, filters, userProfile?.free_swipes, liveOnly]);

    // Heartbeat Presence
    useEffect(() => {
        if (!currentUser) return;
        const interval = setInterval(() => {
            updatePresence(currentUser.id);
        }, 60000 * 4); // Every 4 mins
        updatePresence(currentUser.id);
        return () => clearInterval(interval);
    }, [currentUser]);

    // Realtime Subscription
    useEffect(() => {
        if (!currentUser) return;
        const channel = supabase
            .channel('discovery-realtime')
            .on('postgres_changes', {
                event: 'UPDATE',
                schema: 'public',
                table: 'profiles'
            }, (payload) => {
                const updatedProfile = payload.new;

                // If the user went LIVE and matches current filters, prepend to stack?
                // For now, just update the existing profile in state if present
                setProfiles(prev => prev.map(p => p.id === updatedProfile.id ? { ...p, ...updatedProfile } : p));
            })
            .subscribe();

        return () => supabase.removeChannel(channel);
    }, [currentUser]);

    useEffect(() => {
        if (currentUser && profiles.length > 0) {
            const topProfile = profiles[0];
            trackProfileView(currentUser.id, topProfile.id);
        }
    }, [currentUser, profiles[0]?.id]);

    async function loadBoosts() {
        if (!currentUser) return;
        try {
            const { data } = await getActiveBoosts(currentUser.id);
            setSuperSwipesAvailable(data.superSwipeCount);
        } catch (err) {
            console.error('Error loading boosts:', err);
        }
    }

    // Countdown Timer for Swipe Reset
    useEffect(() => {
        if (!limitReached) return;

        const timer = setInterval(() => {
            const now = new Date();
            const tomorrow = new Date();
            tomorrow.setHours(24, 0, 0, 0);

            const diff = tomorrow - now;
            const hours = Math.floor(diff / (1000 * 60 * 60));
            const minutes = Math.floor((diff / (1000 * 60)) % 60);
            const seconds = Math.floor((diff / 1000) % 60);

            setTimeLeft(`${hours}h ${minutes}m ${seconds}s`);
        }, 1000);

        return () => clearInterval(timer);
    }, [limitReached]);

    const loadProfiles = async (reset = false) => {
        if (!currentUser) return;
        if (reset) setLoading(true);

        try {
            console.log('Fetching discovery profiles...');

            // Sync swipe limits first
            const limitCheck = await checkSwipeLimit(currentUser.id);
            setFreeSwipes(limitCheck.max - limitCheck.used);
            if (!limitCheck.canSwipe) {
                setLimitReached({ used: limitCheck.used, max: limitCheck.max });
            }

            const { data, error } = await getDiscoverProfiles(currentUser.id, { ...filters, liveOnly });

            if (error) {
                console.error('Detailed Load Error:', error);
                addToast('Could not load profiles.', 'error');
            } else {
                // Shuffle photos for each profile to show different "variants"
                const processedProfiles = (data || []).map(profile => {
                    const allPhotos = [...(profile.profile_photos || [])];
                    if (profile.avatar_url && !allPhotos.includes(profile.avatar_url)) {
                        allPhotos.unshift(profile.avatar_url);
                    }

                    // Fisher-Yates shuffle
                    for (let i = allPhotos.length - 1; i > 0; i--) {
                        const j = Math.floor(Math.random() * (i + 1));
                        [allPhotos[i], allPhotos[j]] = [allPhotos[j], allPhotos[i]];
                    }

                    return {
                        ...profile,
                        profile_photos: allPhotos
                    };
                });

                if (reset) {
                    setProfiles(processedProfiles);
                } else {
                    // Prepend/Append based on logic, here we just filter duplicates
                    setProfiles(prev => {
                        const existingIds = new Set(prev.map(p => p.id));
                        const newProfiles = processedProfiles.filter(p => !existingIds.has(p.id));
                        return [...prev, ...newProfiles];
                    });
                }
            }
        } catch (err) {
            console.error('Load Exception:', err);
        } finally {
            if (reset) setLoading(false);
        }
    };

    const handleSwipe = async (direction, swipedProfile, type = 'standard', teaser = null) => {
        // 1. Check Limits for Free Users (Only for RIGHT swipe)
        if (direction === 'right') {
            const { canSwipe, used, max } = await checkSwipeLimit(currentUser.id);
            // We no longer BLOCK the swipe here, because recordSwipe will handle the payment
            // if free swipes are exhausted. We just update the state for UI display.
            if (!canSwipe) {
                // Optional: You could show a small toast here like "Free swipes used. This will cost ₦500."
            }
        }

        // 2. Optimistically remove from list
        const updatedProfiles = profiles.filter(p => p.id !== swipedProfile.id);
        setProfiles(updatedProfiles);

        // 3. Trigger preloading if running low (Phase 1 Fix)
        if (updatedProfiles.length < 5) {
            loadProfiles(false);
        }

        // 4. Record Swipe and Check for Match/Streak
        const result = await recordSwipe(currentUser.id, swipedProfile.id, direction, type, teaser);

        if (result.error) {
            console.error('Swipe Error:', result.error);

            // Only show payment error if it was a RIGHT swipe
            if (direction === 'right') {
                const isInsufficient = result.error.includes('balance') || result.error.includes('funds') || result.error.includes('Insufficient');
                addToast(isInsufficient ? 'Insufficient balance. Top up your wallet!' : 'Transaction failed. Please try again.', 'error');
            } else {
                // For left swipes (passes), show a more generic error if it truly fails
                addToast('Could not record pass. Please try again.', 'error');
            }
            return;
        }

        // Update streak if returned
        if (result.streak) setUserStreak(result.streak);

        if (result.isMatch) {
            // Trigger the High-Fidelity Celebrity Overlay!
            setMatchData(swipedProfile);
        } else if (direction === 'right') {
            // Update free swipes counter locally for real-time feel
            if (freeSwipes > 0 && type === 'standard') {
                setFreeSwipes(prev => Math.max(0, prev - 1));
            }

            if (result.type === 'free') {
                addToast('Standard request sent for free!', 'success');
            } else {
                const amount = type === 'premium' ? '₦5,000' : '₦500';
                addToast(`${type === 'premium' ? 'Premium' : 'Standard'} request sent for ${amount}!`, 'success');
            }
        }

        // 5. Touchpoint A: After 5 Swipes Nudge
        const newCount = swipeCount + 1;
        setSwipeCount(newCount);
        if (newCount === 5 && (userProfile?.completion_score || 0) < 60) {
            setShowNudge(true);
        }
    };

    const handleSuperSwipe = async (swipedProfile) => {
        setProfiles((prev) => prev.filter(p => p.id !== swipedProfile.id));

        const { data, error } = await superSwipe(currentUser.id, swipedProfile);

        if (error) {
            console.error('Super Swipe Error:', error);
            addToast(error, 'error');
            return;
        }

        setSuperSwipesAvailable(prev => Math.max(0, prev - 1));
        addToast(`⭐ Super Swipe sent! ${swipedProfile.full_name || 'They'} will get an instant notification!`, 'success');
    };

    if (loading) return <LoadingSpinner fullScreen text="Finding matches..." />;

    return (
        <div className="discover-page">
            <button className="filter-toggle-btn" onClick={() => setShowFilters(true)}>
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <line x1="4" y1="21" x2="4" y2="14"></line>
                    <line x1="4" y1="10" x2="4" y2="3"></line>
                    <line x1="12" y1="21" x2="12" y2="12"></line>
                    <line x1="12" y1="8" x2="12" y2="3"></line>
                    <line x1="20" y1="21" x2="20" y2="16"></line>
                    <line x1="20" y1="12" x2="20" y2="3"></line>
                    <line x1="1" y1="14" x2="7" y2="14"></line>
                    <line x1="9" y1="8" x2="15" y2="8"></line>
                    <line x1="17" y1="16" x2="23" y2="16"></line>
                </svg>
            </button>

            <div className="swipe-container">
                <div className="live-mode-bar">
                    <div className="live-toggle-pill" onClick={() => setLiveOnly(!liveOnly)}>
                        <div className="live-badge-glow"></div>
                        <span className="live-label">Live Near Me</span>
                        <div className={`live-toggle-switch ${liveOnly ? 'active' : ''}`}>
                            <div className="toggle-circle"></div>
                        </div>
                    </div>
                </div>

                <StatusBubbles />

                {/* Floating Stats Area */}
                <div className="discovery-floating-stats">
                    <StreakIndicator streak={userStreak} badge={userProfile?.current_badge} />
                    <div className="swipes-counter-pill animate-fade-in-right">
                        <span className="pill-icon">⚡</span>
                        <div className="pill-content">
                            <span className="pill-number">{freeSwipes}</span>
                            <span className="pill-label">Swipes Left</span>
                        </div>
                    </div>
                </div>

                {profiles.length === 0 ? (
                    <div className="no-profiles">
                        <div className="pulse-icon">🔍</div>
                        <h2>No more profiles</h2>
                        <p>We couldn't find anyone new matching your filters right now.</p>

                        {(userProfile?.completion_score || 0) < 60 && (
                            <div className="profile-nudge-mini">
                                <p>💡 <strong>Tip:</strong> Profiles under 60% completion appear less often in discovery.</p>
                                <button onClick={() => navigate('/profile/edit')} className="btn btn-link">
                                    Improve Profile
                                </button>
                            </div>
                        )}

                        <button
                            onClick={() => setShowFilters(true)}
                            className="btn btn-primary retry-btn"
                        >
                            Adjust Filters
                        </button>
                    </div>
                ) : (
                    <>
                        <div className="premium-info-container">
                            <button className="info-trigger" onClick={() => setShowInfo(!showInfo)}>i</button>
                            {showInfo && (
                                <div className="swipe-tooltip animate-fade-in-up">
                                    <h4>💎 Swipe Types</h4>
                                    <p>Choosing the right swipe increases your matching chance.</p>
                                    <ul className="tooltip-features">
                                        <li>✅ <strong>Standard (₦500)</strong>: Normal request sent.</li>
                                        <li>🚀 <strong>Premium (₦5,000)</strong>: Direct notification, higher visibility.</li>
                                        <li>⭐ <strong>Super Swipe</strong>: Instant notification to the person!</li>
                                        <li>👑 <strong>Monthly Subscription</strong>: Get 100 free standard swipes!</li>
                                    </ul>
                                </div>
                            )}
                        </div>
                        {profiles.slice(0, 2).reverse().map((profile) => (
                            <SwipeCard
                                key={profile.id}
                                profile={profile}
                                onSwipe={(dir, type, teaser) => handleSwipe(dir, profile, type, teaser)}
                                superSwipesAvailable={superSwipesAvailable}
                                onSuperSwipe={handleSuperSwipe}
                            />
                        ))}

                        <LeaderboardPreview />
                    </>
                )}
            </div>

            {showFilters && (
                <div className="filter-overlay">
                    <div className="filter-box animate-fade-in-up">
                        <div className="filter-header">
                            <h2>Discovery Settings</h2>
                            <button className="close-filters" onClick={() => setShowFilters(false)}>×</button>
                        </div>
                        <div className="filter-body">
                            <div className="filter-section">
                                <label>I'm interested in</label>
                                <div className="filter-options">
                                    {['All', 'Male', 'Female'].map(g => (
                                        <button
                                            key={g}
                                            className={`filter-opt ${filters.gender === g ? 'active' : ''}`}
                                            onClick={() => setFilters(prev => ({ ...prev, gender: g }))}
                                        >
                                            {g}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>
                        <button className="btn btn-primary btn-apply" onClick={() => setShowFilters(false)}>Show Results</button>
                    </div>
                </div>
            )}

            {/* High-Fidelity Match Celebration */}
            <MatchCelebration
                isOpen={!!matchData}
                matchedProfile={matchData}
                userProfile={userProfile}
                onClose={() => setMatchData(null)}
                onMessage={() => navigate('/chat')}
            />

            {/* Limit Reached Overlay */}
            {limitReached && (
                <div className="limit-overlay">
                    <div className="limit-card animate-fade-in-up">
                        <div className="limit-header">
                            <span className="limit-icon">⌛</span>
                            <h2>Daily Limit Reached</h2>
                        </div>

                        <div className="limit-body">
                            <p className="limit-message">
                                You’ve reached today’s limit.<br />
                                <strong>7 people</strong> are still waiting to be discovered 👀
                            </p>

                            <div className="reset-timer">
                                <span className="timer-label">Next reset in:</span>
                                <span className="timer-value">{timeLeft || 'calculating...'}</span>
                            </div>

                            <div className="premium-upsell">
                                <button className="btn btn-premium-unlock" onClick={() => navigate('/premium')}>
                                    🔓 Unlock Unlimited Swipes
                                </button>
                                <p className="premium-price">₦2,900 Premium</p>
                            </div>
                        </div>

                        <button className="limit-close" onClick={() => setLimitReached(null)}>
                            Maybe Later
                        </button>
                    </div>
                </div>
            )}

            {/* Touchpoint A: Session Nudge Overlay */}
            {showNudge && (
                <div className="limit-overlay">
                    <div className="limit-card animate-fade-in-up">
                        <div className="limit-header">
                            <span className="limit-icon">🚀</span>
                            <h2>Boost Your Visibility!</h2>
                        </div>
                        <div className="limit-body">
                            <p className="limit-message">
                                Complete your profile to increase your visibility by <strong>3x</strong>. People naturally want to reach 100%!
                            </p>
                            <div className="premium-upsell">
                                <button className="btn btn-primary btn-block" onClick={() => navigate('/profile/edit')}>
                                    Complete Profile
                                </button>
                            </div>
                        </div>
                        <button className="limit-close" onClick={() => setShowNudge(false)}>
                            Maybe Later
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { uploadAvatar, upsertProfile, uploadVoiceIntro, uploadProfilePhoto } from '../services/profileService';
import { useToast } from '../components/Toast';
import LoadingSpinner from '../components/LoadingSpinner';
import VoiceRecorder from '../components/VoiceRecorder';
import { supabase } from '../lib/supabase';
import './EditProfile.css';

export default function EditProfile() {
    const { currentUser, userProfile, fetchProfile, loading: authLoading } = useAuth();
    const navigate = useNavigate();
    const { addToast } = useToast();
    const fileInputRef = useRef(null);

    const [loading, setLoading] = useState(false);
    const [uploadingAvatar, setUploadingAvatar] = useState(false);
    const [voiceBlob, setVoiceBlob] = useState(null);
    const [formData, setFormData] = useState({
        full_name: '',
        age: '',
        gender: '',
        university: '',
        bio: '',
        avatar_url: '',
        anthem: '',
        location_status: '',
        voice_intro_url: '',
        faculty: '',
        department: '',
        level: '',
        genotype: '',
        mbti: '',
        attraction_goal: '',
        interests: [],
        intro_prompt: '',
        profile_photos: []
    });

    useEffect(() => {
        if (userProfile) {
            setFormData({
                full_name: userProfile.full_name || '',
                age: userProfile.age || '',
                gender: userProfile.gender || '',
                university: userProfile.university || '',
                bio: userProfile.bio || '',
                avatar_url: userProfile.avatar_url || '',
                anthem: userProfile.anthem || '',
                location_status: userProfile.location_status || '',
                voice_intro_url: userProfile.voice_intro_url || '',
                faculty: userProfile.faculty || '',
                department: userProfile.department || '',
                level: userProfile.level || '',
                genotype: userProfile.genotype || '',
                mbti: userProfile.mbti || '',
                attraction_goal: userProfile.attraction_goal || '',
                interests: userProfile.interests || [],
                intro_prompt: userProfile.intro_prompt || '',
                profile_photos: userProfile.profile_photos || []
            });
        }
    }, [userProfile]);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: value
        }));
    };

    const handleAvatarClick = () => {
        fileInputRef.current?.click();
    };

    const handlePhotoUpload = async (e, index) => {
        const file = e.target.files[0];
        if (!file) return;

        setLoading(true);
        try {
            const { url, error } = await uploadProfilePhoto(file, currentUser.id, index);
            if (error) throw new Error(error);

            const newPhotos = [...formData.profile_photos];
            newPhotos[index] = url;

            // Auto-set first photo as avatar if avatar is missing
            const avatarUpdate = !formData.avatar_url && index === 0 ? { avatar_url: url } : {};

            setFormData(prev => ({
                ...prev,
                profile_photos: newPhotos,
                ...avatarUpdate
            }));

            addToast(`Photo ${index + 1} uploaded!`, 'success');
        } catch (err) {
            console.error(err);
            addToast(err.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    const removePhoto = (index) => {
        const newPhotos = [...formData.profile_photos];
        newPhotos[index] = null;
        setFormData(prev => ({ ...prev, profile_photos: newPhotos }));
    };

    const handleVoiceRecording = (blob) => {
        setVoiceBlob(blob);
        // If blob is null, user deleted the recording
        if (!blob) {
            setFormData(prev => ({ ...prev, voice_intro_url: '' }));
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);

        try {
            // Basic validation
            if (!formData.full_name.trim()) {
                throw new Error('Full Name is required');
            }

            let finalVoiceUrl = formData.voice_intro_url;

            // Upload Voice Intro if new blob exists
            if (voiceBlob) {
                const { url, error } = await uploadVoiceIntro(voiceBlob, currentUser.id);
                if (error) throw new Error('Voice upload failed: ' + error);
                finalVoiceUrl = url;
            }

            const profileData = {
                full_name: formData.full_name,
                age: formData.age ? parseInt(formData.age) : null,
                gender: formData.gender ? formData.gender.toLowerCase() : null,
                university: formData.university,
                bio: formData.bio,
                avatar_url: formData.avatar_url,
                anthem: formData.anthem,
                location_status: formData.location_status,
                voice_intro_url: finalVoiceUrl,
                faculty: formData.faculty,
                department: formData.department,
                level: formData.level,
                genotype: formData.genotype,
                mbti: formData.mbti,
                attraction_goal: formData.attraction_goal,
                interests: formData.interests,
                intro_prompt: formData.intro_prompt,
                profile_photos: formData.profile_photos.filter(Boolean), // Clean nulls
                email: currentUser.email,
                updated_at: new Date()
            };

            const { error } = await upsertProfile(currentUser.id, profileData);

            if (error) throw new Error(error);

            await fetchProfile(currentUser.id);

            addToast('Profile updated!', 'success');
            navigate('/profile');
        } catch (err) {
            console.error('Profile update failed:', err);
            addToast(err.message || 'Failed to update profile', 'error');
        } finally {
            setLoading(false);
        }
    };

    if (authLoading) {
        return <LoadingSpinner fullScreen />;
    }

    return (
        <div className="edit-profile-page">
            <div className="edit-profile-container animated fadeIn">
                <header className="edit-profile-header">
                    <h1>Profile Settings</h1>
                    <p>Customize how you appear to others</p>
                </header>

                <form onSubmit={handleSubmit} className="edit-profile-form">
                    {/* PHOTO GRID SECTION */}
                    <section className="form-section">
                        <h2 className="section-title">My Gallery</h2>
                        <div className="photo-grid-2x2">
                            {[0, 1, 2, 3].map((idx) => (
                                <div key={idx} className={`photo-sq-slot ${formData.profile_photos[idx] ? 'filled' : ''}`}>
                                    {formData.profile_photos[idx] ? (
                                        <>
                                            <img src={formData.profile_photos[idx]} alt={`Profile ${idx + 1}`} className="slot-img" />
                                            <button
                                                type="button"
                                                className="delete-sq-btn"
                                                onClick={() => removePhoto(idx)}
                                            >
                                                ×
                                            </button>
                                        </>
                                    ) : (
                                        <label className="slot-sq-empty">
                                            <span className="plus-icon">+</span>
                                            <input
                                                type="file"
                                                onChange={(e) => handlePhotoUpload(e, idx)}
                                                accept="image/*"
                                                hidden
                                            />
                                        </label>
                                    )}
                                    {idx === 0 && <div className="main-badge">MAIN</div>}
                                </div>
                            ))}
                        </div>
                        <p className="section-hint">The first photo is your main avatar used across the app.</p>
                    </section>

                    {/* BASIC INFO SECTION */}
                    <section className="form-section">
                        <h2 className="section-title">Basic Information</h2>

                        <div className="form-row">
                            <div className="form-item">
                                <label>Full Name</label>
                                <input
                                    type="text"
                                    name="full_name"
                                    className="modern-input"
                                    value={formData.full_name}
                                    onChange={handleChange}
                                    placeholder="Your name"
                                />
                            </div>
                            <div className="form-item small">
                                <label>Age</label>
                                <input
                                    type="number"
                                    name="age"
                                    className="modern-input"
                                    value={formData.age}
                                    onChange={handleChange}
                                    min="18"
                                    placeholder="21"
                                />
                            </div>
                        </div>

                        <div className="form-item">
                            <label>Gender</label>
                            <select
                                name="gender"
                                className="modern-input"
                                value={formData.gender}
                                onChange={handleChange}
                            >
                                <option value="">Select Gender</option>
                                <option value="Male">Male</option>
                                <option value="Female">Female</option>
                                <option value="Other">Other</option>
                            </select>
                        </div>

                        <div className="form-item">
                            <label>Bio</label>
                            <textarea
                                name="bio"
                                className="modern-input modern-textarea"
                                value={formData.bio}
                                onChange={handleChange}
                                placeholder="Tell your story..."
                            />
                        </div>
                    </section>

                    {/* STUDENT LIFE SECTION */}
                    <section className="form-section">
                        <h2 className="section-title">Student Life</h2>

                        <div className="form-item">
                            <label>University</label>
                            <input
                                type="text"
                                name="university"
                                className="modern-input"
                                value={formData.university}
                                onChange={handleChange}
                                placeholder="e.g. UNILAG"
                            />
                        </div>

                        <div className="form-row">
                            <div className="form-item">
                                <label>Faculty</label>
                                <input
                                    type="text"
                                    name="faculty"
                                    className="modern-input"
                                    value={formData.faculty}
                                    onChange={handleChange}
                                    placeholder="e.g. Science"
                                />
                            </div>
                            <div className="form-item">
                                <label>Level</label>
                                <select
                                    name="level"
                                    className="modern-input"
                                    value={formData.level}
                                    onChange={handleChange}
                                >
                                    <option value="">Select Level</option>
                                    <option value="100 Lvl">100 Lvl</option>
                                    <option value="200 Lvl">200 Lvl</option>
                                    <option value="300 Lvl">300 Lvl</option>
                                    <option value="400 Lvl">400 Lvl</option>
                                    <option value="500 Lvl">500 Lvl</option>
                                    <option value="Postgrad">Postgrad</option>
                                </select>
                            </div>
                        </div>

                        <div className="form-row">
                            <div className="form-item">
                                <label>Genotype</label>
                                <select
                                    name="genotype"
                                    className="modern-input"
                                    value={formData.genotype}
                                    onChange={handleChange}
                                >
                                    <option value="">Select</option>
                                    <option value="AA">AA</option>
                                    <option value="AS">AS</option>
                                    <option value="SS">SS</option>
                                </select>
                            </div>
                            <div className="form-item">
                                <label>MBTI</label>
                                <input
                                    type="text"
                                    name="mbti"
                                    className="modern-input"
                                    value={formData.mbti}
                                    onChange={handleChange}
                                    placeholder="INFJ"
                                    maxLength="4"
                                />
                            </div>
                        </div>
                    </section>

                    {/* VIBE CHECK SECTION */}
                    <section className="form-section vibe-accent">
                        <h2 className="section-title">✨ Vibe Check</h2>

                        <div className="form-item">
                            <label>My Anthem 🎵</label>
                            <input
                                type="text"
                                name="anthem"
                                className="modern-input"
                                value={formData.anthem}
                                onChange={handleChange}
                                placeholder="Favorite song..."
                            />
                        </div>

                        <div className="form-item">
                            <label>Current Status 📍</label>
                            <input
                                type="text"
                                name="location_status"
                                className="modern-input"
                                value={formData.location_status}
                                onChange={handleChange}
                                placeholder="What are you up to?"
                            />
                        </div>

                        <div className="form-item">
                            <VoiceRecorder
                                onRecordingComplete={handleVoiceRecording}
                                existingAudioUrl={formData.voice_intro_url}
                            />
                        </div>

                        <div className="form-item">
                            <label>Interests 🎨</label>
                            <div className="interests-flex">
                                {['Coding', 'Music', 'Sports', 'Art', 'Gaming', 'Travel', 'Food', 'Reading', 'Dancing', 'Tech', 'Fashion', 'Fitness'].map(interest => (
                                    <button
                                        key={interest}
                                        type="button"
                                        className={`vibe-chip ${formData.interests.includes(interest) ? 'active' : ''}`}
                                        onClick={() => {
                                            const newInterests = formData.interests.includes(interest)
                                                ? formData.interests.filter(i => i !== interest)
                                                : [...formData.interests, interest];
                                            setFormData(prev => ({ ...prev, interests: newInterests }));
                                        }}
                                    >
                                        {interest}
                                    </button>
                                ))}
                            </div>
                        </div>
                    </section>

                    <div className="form-sticky-actions">
                        <button
                            type="button"
                            className="modern-btn secondary"
                            onClick={() => navigate('/profile')}
                        >
                            Back
                        </button>
                        <button
                            type="submit"
                            className="modern-btn primary"
                            disabled={loading}
                        >
                            {loading ? <LoadingSpinner size="small" color="white" /> : 'Save Changes'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

