import { useState, useEffect } from 'react';
import { getLeaderboards } from '../services/leaderboardService';
import { useAuth } from '../contexts/AuthContext';
import LoadingSpinner from '../components/LoadingSpinner';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';

const UserAvatar = ({ user, size = "md", rank = 0, activeTab }) => {
    const navigate = useNavigate();
    const getAvatar = (u) => u.avatar_url || `https://ui-avatars.com/api/?name=${encodeURIComponent(u.full_name)}&background=random`;

    // Uniform size for Top 3 (Hall of Fame) to be exactly the same
    const sizes = {
        sm: "w-12 h-12 rounded-xl", // List view
        md: "w-24 h-24 rounded-full", // Not used for top 3 anymore
        lg: "w-20 h-20 sm:w-28 sm:h-28 rounded-full"  // Responsive: 80px mobile, 112px desktop
    };

    const frameStyles = {
        1: "border-yellow-400 shadow-[0_0_20px_rgba(250,204,21,0.6)] bg-gradient-to-br from-yellow-200 via-yellow-500 to-yellow-800 ring-4 ring-yellow-500/20",
        2: "border-slate-300 shadow-[0_0_15px_rgba(203,213,225,0.4)] bg-gradient-to-br from-white via-slate-400 to-slate-700 ring-4 ring-slate-400/20",
        3: "border-amber-700 shadow-[0_0_15px_rgba(180,83,9,0.4)] bg-gradient-to-br from-amber-400 via-amber-700 to-amber-950 ring-4 ring-amber-700/20",
        default: "border-white/10 bg-white/5"
    };

    const currentFrame = frameStyles[rank] || frameStyles.default;
    const isTop3 = rank >= 1 && rank <= 3;

    return (
        <div className="relative group cursor-pointer" onClick={() => navigate(`/profile/${user.profile_id || user.id}`)}>
            {/* Outer Frame Wrapper */}
            <div className={`
                ${isTop3 ? 'p-1.5' : 'p-1'} 
                ${size === 'sm' ? 'rounded-2xl' : 'rounded-full'} 
                ${currentFrame} 
                transition-transform duration-500 group-hover:scale-105
            `}>
                <div className={`bg-[#0a0a0c] p-0.5 ${size === 'sm' ? 'rounded-[13px]' : 'rounded-full'} overflow-hidden`}>
                    <img
                        src={getAvatar(user)}
                        className={`
                            ${sizes[size]} 
                            object-cover 
                            ${size === 'sm' ? 'grayscale group-hover:grayscale-0' : ''} 
                            transition-all duration-500
                        `}
                        alt={user.full_name}
                    />
                </div>
            </div>

            {rank > 0 && (
                <div className={`
                    absolute left-1/2 -translate-x-1/2 z-20 shadow-lg border-2 border-[#0a0a0c]
                    ${rank === 1 ? '-bottom-4 bg-yellow-500 text-black px-3 py-0.5 text-xs font-black' :
                        rank === 2 ? '-bottom-3 bg-slate-300 text-black w-7 h-7 flex items-center justify-center text-[10px] font-black' :
                            rank === 3 ? '-bottom-3 bg-amber-700 text-white w-7 h-7 flex items-center justify-center text-[10px] font-black' :
                                'hidden'} // Hide rank badge for list items
                    rounded-full
                `}>
                    {rank}
                </div>
            )}
        </div>
    );
};

export default function Leaderboard() {
    const { currentUser } = useAuth();
    const navigate = useNavigate();
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('wanted'); // 'wanted' or 'spenders'
    const [data, setData] = useState({ mostWanted: [], bigSpenders: [] });

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const { mostWanted, bigSpenders } = await getLeaderboards();
            setData({ mostWanted: mostWanted || [], bigSpenders: bigSpenders || [] });
        } catch (error) {
            console.error("Leaderboard load error:", error);
        } finally {
            setLoading(false);
        }
    };

    const displayList = activeTab === 'wanted' ? data.mostWanted : data.bigSpenders;
    const topThree = displayList.slice(0, 3);
    const runnersUp = displayList.slice(3);

    if (loading) return <LoadingSpinner fullScreen text="Ranking University Elite..." />;

    return (
        <div className="min-h-screen bg-[#0a0a0c] pb-28 text-white selection:bg-rose-500/30">
            <div className="fixed inset-0 overflow-hidden pointer-events-none">
                <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full" />
                <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-rose-600/10 blur-[120px] rounded-full" />
            </div>

            <div className="relative px-4 pt-8 max-w-2xl mx-auto">
                <motion.div
                    initial={{ opacity: 0, y: -20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="text-center mb-10"
                >
                    <div className="inline-block px-3 py-1 bg-white/5 border border-white/10 rounded-full mb-3">
                        <span className="text-[10px] font-bold uppercase tracking-[0.2em] text-rose-500">The Hall of Fame</span>
                    </div>
                    <h1 className="text-5xl font-black italic tracking-tighter bg-gradient-to-b from-white to-gray-500 bg-clip-text text-transparent italic leading-tight uppercase">
                        CD Elite
                    </h1>
                </motion.div>

                <div className="flex justify-center mb-12">
                    <div className="relative bg-[#1a1a1e] p-1 rounded-2xl border border-white/5 flex w-full max-w-[320px] shadow-2xl">
                        <div
                            className={`absolute top-1 bottom-1 w-[calc(50%-4px)] bg-gradient-to-br from-rose-500 to-purple-600 rounded-xl transition-all duration-500 ease-[cubic-bezier(0.34,1.56,0.64,1)] ${activeTab === 'wanted' ? 'left-1' : 'left-[calc(50%+2px)]'} shadow-lg shadow-rose-500/20`}
                        />
                        <button
                            onClick={() => setActiveTab('wanted')}
                            className={`relative flex-1 py-3 text-xs font-black uppercase tracking-widest z-10 transition-colors duration-300 ${activeTab === 'wanted' ? 'text-white' : 'text-gray-500 hover:text-gray-300'}`}
                        >
                            Most Wanted 💃
                        </button>
                        <button
                            onClick={() => setActiveTab('spenders')}
                            className={`relative flex-1 py-3 text-xs font-black uppercase tracking-widest z-10 transition-colors duration-300 ${activeTab === 'spenders' ? 'text-white' : 'text-gray-500 hover:text-gray-300'}`}
                        >
                            Spenders 💸
                        </button>
                    </div>
                </div>

                <AnimatePresence mode="wait">
                    <motion.div
                        key={activeTab}
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        exit={{ opacity: 0, scale: 1.05 }}
                        transition={{ duration: 0.4, ease: "easeOut" }}
                    >
                        <div className="relative flex justify-center items-end h-[320px] mb-12 px-2">
                            {/* 2nd Place */}
                            {topThree[1] && (
                                <div className="flex flex-col items-center w-1/3 group">
                                    <div className="relative mb-6">
                                        <div className="absolute inset-[-15px] bg-gray-400/5 blur-3xl rounded-full" />
                                        <UserAvatar user={topThree[1]} size="lg" rank={2} activeTab={activeTab} />
                                    </div>
                                    <div className="w-full bg-gradient-to-t from-gray-800/10 to-gray-400/20 backdrop-blur-sm border-t border-gray-400/30 h-28 rounded-t-2xl flex flex-col items-center justify-center p-2">
                                        <p className="text-[10px] font-bold text-gray-300 truncate w-full text-center uppercase tracking-tight">{topThree[1].full_name.split(' ')[0]}</p>
                                        <p className="text-sm font-black text-white mt-1">
                                            {activeTab === 'wanted' ? topThree[1].premium_swipes_received : `₦${(topThree[1].total_spent / 1000).toFixed(1)}k`}
                                        </p>
                                    </div>
                                </div>
                            )}

                            {/* 1st Place */}
                            {topThree[0] && (
                                <div className="flex flex-col items-center w-1/3 z-10 group">
                                    <div className="relative mb-8">
                                        <motion.div
                                            animate={{ y: [0, -10, 0] }}
                                            transition={{ repeat: Infinity, duration: 4 }}
                                            className="absolute -top-10 left-1/2 -translate-x-1/2 text-3xl drop-shadow-lg z-30"
                                        >
                                            👑
                                        </motion.div>
                                        <div className="absolute inset-[-20px] bg-yellow-500/10 blur-3xl opacity-50 rounded-full" />
                                        <UserAvatar user={topThree[0]} size="lg" rank={1} activeTab={activeTab} />
                                    </div>
                                    <div className="w-full bg-gradient-to-t from-yellow-500/10 to-yellow-500/30 backdrop-blur-md border-t border-yellow-500/50 h-36 rounded-t-3xl flex flex-col items-center justify-center p-2 shadow-2xl">
                                        <p className="text-xs font-black text-yellow-100 truncate w-full text-center uppercase tracking-wider">{topThree[0].full_name.split(' ')[0]}</p>
                                        <p className="text-xl font-black text-white mt-1 drop-shadow-sm">
                                            {activeTab === 'wanted' ? topThree[0].premium_swipes_received : `₦${(topThree[0].total_spent / 1000).toFixed(1)}k`}
                                        </p>
                                    </div>
                                </div>
                            )}

                            {/* 3rd Place */}
                            {topThree[2] && (
                                <div className="flex flex-col items-center w-1/3 group">
                                    <div className="relative mb-6">
                                        <div className="absolute inset-[-15px] bg-amber-700/5 blur-3xl rounded-full" />
                                        <UserAvatar user={topThree[2]} size="lg" rank={3} activeTab={activeTab} />
                                    </div>
                                    <div className="w-full bg-gradient-to-t from-amber-700/10 to-amber-700/20 backdrop-blur-sm border-t border-amber-700/30 h-24 rounded-t-2xl flex flex-col items-center justify-center p-2">
                                        <p className="text-[10px] font-bold text-gray-300 truncate w-full text-center uppercase tracking-tight">{topThree[2].full_name.split(' ')[0]}</p>
                                        <p className="text-sm font-black text-white mt-1">
                                            {activeTab === 'wanted' ? topThree[2].premium_swipes_received : `₦${(topThree[2].total_spent / 1000).toFixed(1)}k`}
                                        </p>
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="space-y-3">
                            <h3 className="text-[10px] font-black tracking-[0.3em] text-gray-500 uppercase mb-4 ml-2">Rising Stars</h3>
                            {runnersUp.map((user, index) => (
                                <motion.div
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: index * 0.05 }}
                                    key={user.id}
                                    className="group relative bg-[#16161a] hover:bg-[#1e1e24] p-3 flex items-center rounded-2xl border border-white/5 transition-all duration-300 hover:scale-[1.02] cursor-pointer"
                                    onClick={() => navigate(`/profile/${user.profile_id || user.id}`)}
                                >
                                    <div className="w-10 text-xs font-black text-gray-600 group-hover:text-rose-500 transition-colors">
                                        {(index + 4).toString().padStart(2, '0')}
                                    </div>

                                    <UserAvatar user={user} size="sm" activeTab={activeTab} />

                                    <div className="flex-1 ml-4 min-w-0">
                                        <p className="text-sm font-bold text-white group-hover:text-rose-400 transition-colors truncate uppercase tracking-tight">{user.full_name}</p>
                                        <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mt-0.5">{user.university || 'CD Elite'}</p>
                                    </div>
                                    <div className="text-right pl-4">
                                        <div className="text-sm font-black text-white group-hover:text-rose-500 transition-colors">
                                            {activeTab === 'wanted' ? user.premium_swipes_received : `₦${(user.total_spent / 1000).toFixed(1)}k`}
                                        </div>
                                        <div className="text-[8px] font-bold text-gray-600 uppercase tracking-tighter">
                                            {activeTab === 'wanted' ? 'Fans' : 'Spent'}
                                        </div>
                                    </div>
                                </motion.div>
                            ))}
                        </div>
                    </motion.div>
                </AnimatePresence>
            </div>
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { uploadProfilePhoto, upsertProfile } from '../services/profileService';
import { useToast } from '../components/Toast';
import LoadingSpinner from '../components/LoadingSpinner';
import { motion, AnimatePresence } from 'framer-motion';
import './MiniProfileSetup.css';

export default function MiniProfileSetup() {
    const { currentUser, userProfile, fetchProfile, loading: authLoading } = useAuth();
    const navigate = useNavigate();
    const { addToast } = useToast();
    const [loading, setLoading] = useState(false);
    const [step, setStep] = useState(1); // 1: Bio & Interests, 2: Photos

    const [formData, setFormData] = useState({
        full_name: '',
        bio: '',
        interests: [],
        university: '',
        age: '',
        profile_photos: [null, null, null, null]
    });

    useEffect(() => {
        if (userProfile) {
            setFormData(prev => ({
                ...prev,
                full_name: userProfile.full_name || '',
                bio: userProfile.bio || '',
                interests: userProfile.interests || [],
                university: userProfile.university || '',
                age: userProfile.age || '',
                profile_photos: userProfile.profile_photos && userProfile.profile_photos.length >= 4
                    ? userProfile.profile_photos.slice(0, 4)
                    : [null, null, null, null]
            }));
        }
    }, [userProfile]);

    const syncProfileField = async (field, value) => {
        if (!currentUser) return;
        try {
            const updates = { [field]: value, updated_at: new Date() };
            // For complex fields like profile_photos, we might need special handling
            // but for simple fields like bio, full_name, it's fine.
            await upsertProfile(currentUser.id, updates);
        } catch (err) {
            console.error(`Failed to sync ${field}:`, err);
        }
    };

    const handleChange = (field, value) => {
        setFormData(prev => ({ ...prev, [field]: value }));
    };

    const handleBlur = (field) => {
        syncProfileField(field, formData[field]);
    };

    const handleInterestToggle = (interest) => {
        setFormData(prev => {
            const interests = prev.interests.includes(interest)
                ? prev.interests.filter(i => i !== interest)
                : [...prev.interests, interest];
            syncProfileField('interests', interests);
            return { ...prev, interests };
        });
    };

    const handlePhotoUpload = async (e, index) => {
        const file = e.target.files[0];
        if (!file) return;

        setLoading(true);
        try {
            const { url, error } = await uploadProfilePhoto(file, currentUser.id, index);
            if (error) throw new Error(error);

            const newPhotos = [...formData.profile_photos];
            newPhotos[index] = url;

            setFormData(prev => ({
                ...prev,
                profile_photos: newPhotos
            }));

            // Real-time sync to indexed profile
            const updates = {
                profile_photos: newPhotos.filter(Boolean),
                updated_at: new Date()
            };

            // Set first photo as main avatar automatically for discovery
            if (index === 0 || !userProfile?.avatar_url) {
                updates.avatar_url = url;
            }

            await upsertProfile(currentUser.id, updates);

            addToast(`Photo ${index + 1} uploaded!`, 'success');
        } catch (err) {
            addToast(err.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    const isStep1Complete = formData.full_name.trim() !== '' &&
        formData.bio.trim().length >= 10 &&
        formData.interests.length >= 3 &&
        formData.age !== '' &&
        formData.university !== '';

    const isStep2Complete = formData.profile_photos.filter(Boolean).length === 4;

    const handleSubmit = async () => {
        if (!isStep1Complete || !isStep2Complete) {
            addToast('Please complete all details and upload 4 photos!', 'error');
            return;
        }

        setLoading(true);
        try {
            const profileData = {
                full_name: formData.full_name,
                bio: formData.bio,
                interests: formData.interests,
                university: formData.university,
                age: parseInt(formData.age),
                profile_photos: formData.profile_photos,
                avatar_url: formData.profile_photos[0], // Set first photo as avatar
                updated_at: new Date()
            };

            const { error } = await upsertProfile(currentUser.id, profileData);
            if (error) throw new Error(error);

            await fetchProfile(currentUser.id);
            addToast('Profile ready! Welcome to Discovery 💕', 'success');
            navigate('/discover');
        } catch (err) {
            addToast(err.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    if (authLoading) return <LoadingSpinner fullScreen />;

    const INTERESTS_OPTIONS = ['Coding', 'Music', 'Sports', 'Art', 'Gaming', 'Travel', 'Food', 'Reading', 'Dancing', 'Tech', 'Fashion', 'Fitness'];

    return (
        <div className="mini-setup-page">
            <div className="setup-container">
                <div className="setup-header">
                    <motion.h1
                        initial={{ opacity: 0, y: -20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="setup-title"
                    >
                        Finish Your Profile ✨
                    </motion.h1>
                    <p className="setup-subtitle">You're just a few steps away from meeting matches.</p>
                </div>

                <div className="setup-progress-container">
                    <div className="setup-progress-bar">
                        <motion.div
                            className="progress-fill"
                            initial={{ width: '0%' }}
                            animate={{ width: step === 1 ? '50%' : '100%' }}
                        />
                    </div>
                </div>

                <AnimatePresence mode="wait">
                    {step === 1 ? (
                        <motion.div
                            key="step1"
                            initial={{ opacity: 0, x: 20 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: -20 }}
                            className="setup-step"
                        >
                            <h2 className="step-title">The Basics</h2>

                            <div className="input-field-group">
                                <label className={formData.full_name ? 'completed' : ''}>Full Name</label>
                                <input
                                    type="text"
                                    placeholder="What should people call you?"
                                    value={formData.full_name}
                                    onChange={(e) => handleChange('full_name', e.target.value)}
                                    onBlur={() => handleBlur('full_name')}
                                    className={formData.full_name ? 'input-completed' : ''}
                                />
                            </div>

                            <div className="row-group">
                                <div className="input-field-group">
                                    <label className={formData.age ? 'completed' : ''}>Age</label>
                                    <input
                                        type="number"
                                        placeholder="Age"
                                        value={formData.age}
                                        onChange={(e) => handleChange('age', e.target.value)}
                                        onBlur={() => handleBlur('age')}
                                        className={formData.age ? 'input-completed' : ''}
                                    />
                                </div>
                                <div className="input-field-group">
                                    <label className={formData.university ? 'completed' : ''}>University</label>
                                    <input
                                        type="text"
                                        placeholder="University"
                                        value={formData.university}
                                        onChange={(e) => handleChange('university', e.target.value)}
                                        onBlur={() => handleBlur('university')}
                                        className={formData.university ? 'input-completed' : ''}
                                    />
                                </div>
                            </div>

                            <div className="input-field-group">
                                <label className={formData.bio.length >= 10 ? 'completed' : ''}>Bio (Min 10 chars)</label>
                                <textarea
                                    placeholder="Tell the world about yourself..."
                                    value={formData.bio}
                                    onChange={(e) => handleChange('bio', e.target.value)}
                                    onBlur={() => handleBlur('bio')}
                                    className={formData.bio.length >= 10 ? 'input-completed' : ''}
                                />
                            </div>

                            <div className="interests-section">
                                <label className={formData.interests.length >= 3 ? 'completed' : ''}>Interests (Select 3+)</label>
                                <div className="setup-interests-grid">
                                    {INTERESTS_OPTIONS.map(interest => (
                                        <button
                                            key={interest}
                                            className={`setup-interest-chip ${formData.interests.includes(interest) ? 'active' : ''}`}
                                            onClick={() => handleInterestToggle(interest)}
                                        >
                                            {interest}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <button
                                className="setup-next-btn"
                                onClick={() => setStep(2)}
                                disabled={!isStep1Complete}
                            >
                                Next Step ➔
                            </button>
                        </motion.div>
                    ) : (
                        <motion.div
                            key="step2"
                            initial={{ opacity: 0, x: 20 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: -20 }}
                            className="setup-step"
                        >
                            <h2 className="step-title">Add 4 Photos</h2>
                            <p className="step-desc">Profiles with 4+ photos get 80% more matches!</p>

                            <div className="setup-photo-grid">
                                {[0, 1, 2, 3].map((idx) => (
                                    <div key={idx} className={`setup-photo-slot ${formData.profile_photos[idx] ? 'filled' : ''}`}>
                                        {formData.profile_photos[idx] ? (
                                            <img src={formData.profile_photos[idx]} alt="Profile" />
                                        ) : (
                                            <label className="photo-upload-label">
                                                <span className="plus-icon">+</span>
                                                <input
                                                    type="file"
                                                    accept="image/*"
                                                    onChange={(e) => handlePhotoUpload(e, idx)}
                                                    hidden
                                                    disabled={loading}
                                                />
                                            </label>
                                        )}
                                        {loading && !formData.profile_photos[idx] && (
                                            <div className="photo-loading-overlay">
                                                <div className="mini-spinner"></div>
                                            </div>
                                        )}
                                    </div>
                                ))}
                            </div>

                            <div className="setup-actions">
                                <button className="setup-back-btn" onClick={() => setStep(1)}>Back</button>
                                <button
                                    className="setup-finish-btn"
                                    disabled={!isStep2Complete || loading}
                                    onClick={handleSubmit}
                                >
                                    {loading ? 'Saving...' : 'Finish Setup! 🚀'}
                                </button>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { initializePaystack, createTransaction, completeTransaction, getSubscription, getWallet, payWithWallet, purchaseBoost, getActiveBoosts } from '../services/paymentService';
import { useToast } from '../components/Toast';
import LoadingSpinner from '../components/LoadingSpinner';
import { motion, AnimatePresence } from 'framer-motion';
import './PremiumUpgrade.css';

export default function PremiumUpgrade() {
    const { currentUser, userProfile } = useAuth();
    const { addToast } = useToast();
    const [loading, setLoading] = useState(true);
    const [subscription, setSubscription] = useState(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [wallet, setWallet] = useState(null);
    const [boostData, setBoostData] = useState({ hasBoosted: false, activeBoost: null, superSwipeCount: 0 });
    const [processingBoost, setProcessingBoost] = useState(null);
    const [expandedFeature, setExpandedFeature] = useState(null);

    useEffect(() => {
        if (currentUser) {
            loadSubscription();
            loadWallet();
            loadBoosts();
        }
    }, [currentUser]);

    async function loadWallet() {
        try {
            const { data } = await getWallet(currentUser.id);
            setWallet(data);
        } catch (err) {
            console.error('Error loading wallet:', err);
        }
    }

    async function loadBoosts() {
        try {
            const { data } = await getActiveBoosts(currentUser.id);
            setBoostData(data);
        } catch (err) {
            console.error('Error loading boosts:', err);
        }
    }

    async function loadSubscription() {
        setLoading(true);
        try {
            const { data, error } = await getSubscription(currentUser.id);
            if (error && error.code !== 'PGRST116') throw error;
            setSubscription(data);
        } catch (err) {
            console.error('Error loading subscription:', err);
        } finally {
            setLoading(false);
        }
    }

    const handleSubscribe = async () => {
        setIsProcessing(true);
        try {
            const { data: tx, error: txError } = await createTransaction({
                user_id: currentUser.id,
                type: 'subscription',
                amount: 2900,
                status: 'pending',
                description: 'College Date Premium Subscription'
            });

            if (txError) throw txError;

            initializePaystack({
                public_key: import.meta.env.VITE_PAYSTACK_PUBLIC_KEY,
                reference: `CD-SUB-${tx.id}`,
                amount: 2900,
                email: currentUser.email,
                metadata: {
                    user_id: currentUser.id,
                    transaction_id: tx.id,
                    type: 'subscription'
                },
                callback: async (response) => {
                    const { error: completeError } = await completeTransaction(
                        tx.id,
                        'success',
                        response.reference,
                        response
                    );

                    if (completeError) {
                        addToast('Payment successful but activation failed. Contact support.', 'error');
                    } else {
                        addToast('Welcome to Premium! Your features are now unlocked.', 'success');
                        loadSubscription();
                    }
                    setIsProcessing(false);
                },
                onClose: () => {
                    setIsProcessing(false);
                }
            });

        } catch (err) {
            console.error('Subscription error:', err);
            addToast(err.message, 'error');
            setIsProcessing(false);
        }
    };

    const handlePayWithWallet = async () => {
        if (!wallet || wallet.available_balance < 2900) {
            addToast('Insufficient wallet balance', 'error');
            return;
        }

        setIsProcessing(true);
        try {
            const { error } = await payWithWallet(
                currentUser.id,
                2900,
                'subscription',
                'College Date Premium Subscription'
            );

            if (error) throw error;

            addToast('Welcome to Premium! Paid via wallet balance.', 'success');
            loadSubscription();
            loadWallet();
        } catch (err) {
            console.error('Wallet payment error:', err);
            addToast(err.message || 'Payment failed', 'error');
        } finally {
            setIsProcessing(false);
        }
    };

    const handlePurchaseBoost = async (boostType) => {
        const label = boostType === '24h_boost' ? '24h Boost' : 'Super Swipe';
        const cost = boostType === '24h_boost' ? 1000 : 500;

        if (boostType === '24h_boost' && boostData.hasBoosted) {
            addToast('You already have an active 24h Boost!', 'warning');
            return;
        }

        setProcessingBoost(boostType);
        try {
            const { data, error } = await purchaseBoost(currentUser.id, boostType);

            if (error) {
                addToast(error, 'error');
                return;
            }

            addToast(`${label} purchased for ₦${cost.toLocaleString()}! 🎉`, 'success');
            loadWallet();
            loadBoosts();
        } catch (err) {
            console.error(`Error purchasing ${label}:`, err);
            addToast(err.message || 'Purchase failed', 'error');
        } finally {
            setProcessingBoost(null);
        }
    };

    function getBoostTimeRemaining() {
        if (!boostData.activeBoost) return null;
        const expiresAt = new Date(boostData.activeBoost.expires_at);
        const now = new Date();
        const diffMs = expiresAt - now;
        if (diffMs <= 0) return null;
        const hours = Math.floor(diffMs / (1000 * 60 * 60));
        const minutes = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));
        return `${hours}h ${minutes}m`;
    }

    const toggleFeature = (id) => {
        setExpandedFeature(expandedFeature === id ? null : id);
    };

    if (loading) return <LoadingSpinner fullScreen />;

    const isPremium = subscription?.plan_type === 'Premium' && subscription?.status === 'active';
    const boostTimeRemaining = getBoostTimeRemaining();

    const premiumFeatures = [
        {
            id: 'unlimited',
            icon: '✨',
            title: 'Unlimited Swipes',
            short: 'No daily limits',
            detail: 'Free users get 10 swipes per day. Premium removes all limits — swipe as much as you want, anytime.'
        },
        {
            id: 'viewed',
            icon: '👀',
            title: 'Who Viewed Me',
            short: 'See your admirers',
            detail: 'See exactly who checked out your profile. Know who\'s interested before they even swipe — give yourself the advantage.'
        },
        {
            id: 'priority',
            icon: '🚀',
            title: 'Priority Discovery',
            short: 'Be seen first',
            detail: 'Your profile appears at the top of the stack for other users. More visibility = more matches. Simple.'
        },
        {
            id: 'filters',
            icon: '🎓',
            title: 'Advanced Filters',
            short: 'School, Course, Level',
            detail: 'Filter by specific university, department, and year level. Find exactly who you\'re looking for on campus.'
        },
        {
            id: 'weekly',
            icon: '⚡',
            title: 'Weekly Boost',
            short: '1 free boost every week',
            detail: 'Get a free 24h visibility boost every week — worth ₦1,000 each time. That\'s ₦4,000+ saved monthly.'
        },
        {
            id: 'badge',
            icon: '🛡️',
            title: 'Premium Badge',
            short: 'Stand out on campus',
            detail: 'A verified premium badge on your profile. Shows you\'re serious about connecting. Proven to increase match rate by 3x.'
        }
    ];

    return (
        <div className="premium-page animate-fade-in">
            <header className="premium-header">
                <motion.div
                    initial={{ scale: 0.8, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    className="premium-badge-large"
                >
                    💎
                </motion.div>
                <h1>{isPremium ? 'You are Premium' : 'Upgrade to Premium'}</h1>
                <p>Unlock the full power of College Date</p>
            </header>

            {/* ── Swipe Types Comparison ── */}
            <div className="comparison-section">
                <h2>💡 How Swiping Works</h2>
                <p className="comparison-subtitle">Every right-swipe sends a connection request. Choose the power behind yours.</p>
                <div className="comparison-grid">
                    <motion.div className="comparison-card" whileHover={{ y: -4 }}>
                        <div className="comparison-tier">Standard</div>
                        <div className="comparison-price">₦500<span>/swipe</span></div>
                        <ul className="comparison-perks">
                            <li>✅ Send connection request</li>
                            <li>✅ They see you in their requests</li>
                            <li>❌ No notification sent</li>
                            <li>❌ Normal queue position</li>
                        </ul>
                    </motion.div>
                    <motion.div className="comparison-card comparison-popular" whileHover={{ y: -4 }}>
                        <div className="comparison-ribbon">MOST IMPACTFUL</div>
                        <div className="comparison-tier">Premium Swipe</div>
                        <div className="comparison-price">₦5,000<span>/swipe</span></div>
                        <ul className="comparison-perks">
                            <li>✅ Send connection request</li>
                            <li>✅ Attach a personal note</li>
                            <li>✅ Higher visibility in queue</li>
                            <li>✅ They see your note first</li>
                        </ul>
                    </motion.div>
                    <motion.div className="comparison-card comparison-star" whileHover={{ y: -4 }}>
                        <div className="comparison-tier">Super Swipe</div>
                        <div className="comparison-price">₦500<span>/credit</span></div>
                        <ul className="comparison-perks">
                            <li>✅ Send connection request</li>
                            <li>✅ <strong>Instant notification</strong></li>
                            <li>✅ Priority flag in their queue</li>
                            <li>✅ Buy credits, use anytime</li>
                        </ul>
                    </motion.div>
                </div>
            </div>

            {/* ── Premium Subscription ── */}
            <div className="premium-grid">
                <div className="premium-card">
                    <h3>Premium Subscription</h3>
                    <ul className="feature-list">
                        {premiumFeatures.map((f) => (
                            <li key={f.id} onClick={() => toggleFeature(f.id)} className={`feature-row ${expandedFeature === f.id ? 'expanded' : ''}`}>
                                <div className="feature-header">
                                    <span className="feature-icon-text">{f.icon}</span>
                                    <div className="feature-text">
                                        <strong>{f.title}</strong> — {f.short}
                                    </div>
                                    <span className="feature-chevron">{expandedFeature === f.id ? '▲' : '▼'}</span>
                                </div>
                                <AnimatePresence>
                                    {expandedFeature === f.id && (
                                        <motion.div
                                            className="feature-detail"
                                            initial={{ height: 0, opacity: 0 }}
                                            animate={{ height: 'auto', opacity: 1 }}
                                            exit={{ height: 0, opacity: 0 }}
                                            transition={{ duration: 0.25 }}
                                        >
                                            {f.detail}
                                        </motion.div>
                                    )}
                                </AnimatePresence>
                            </li>
                        ))}
                    </ul>

                    {isPremium ? (
                        <div className="active-subscription">
                            <p>Your subscription is active until:</p>
                            <p className="expiry-date">{new Date(subscription.current_period_end).toLocaleDateString()}</p>
                            <button className="btn btn-secondary" disabled>Premium Active</button>
                        </div>
                    ) : (
                        <div className="pricing-box">
                            <div className="price">
                                <span className="currency">₦</span>
                                <span className="amount">2,900</span>
                                <span className="period">/month</span>
                            </div>
                            <button
                                className="btn btn-primary btn-upgrade"
                                onClick={handleSubscribe}
                                disabled={isProcessing}
                            >
                                {isProcessing ? 'Processing...' : 'Upgrade Now'}
                            </button>

                            {wallet?.available_balance >= 2900 && (
                                <button
                                    className="btn btn-outline btn-wallet-pay"
                                    onClick={handlePayWithWallet}
                                    disabled={isProcessing}
                                    style={{ marginTop: '0.75rem', width: '100%' }}
                                >
                                    {isProcessing ? 'Processing...' : `Pay with Wallet (₦${wallet.available_balance.toLocaleString()})`}
                                </button>
                            )}

                            <p className="secure-text">🔒 Secure payment via Paystack</p>
                        </div>
                    )}
                </div>
            </div>

            {/* ── One-Time Boosts ── */}
            <div className="microtransactions">
                <h2>⚡ One-Time Boosts</h2>
                <p className="boost-subtitle">No subscription needed. Buy once, use immediately. Deducted from your wallet balance.</p>
                <div className="boost-grid">
                    <div className={`boost-item ${boostData.hasBoosted ? 'boost-active' : ''}`}>
                        <span className="boost-icon">🚀</span>
                        <h4>24h Boost</h4>
                        <p className="boost-desc">Your profile gets <strong>2× visibility</strong> for 24 hours. Appear at the top of everyone's Discover feed on campus.</p>
                        {boostData.hasBoosted && boostTimeRemaining ? (
                            <div className="boost-active-badge">
                                <span className="boost-pulse"></span>
                                Active — {boostTimeRemaining} left
                            </div>
                        ) : (
                            <button
                                className="btn btn-outline btn-boost"
                                onClick={() => handlePurchaseBoost('24h_boost')}
                                disabled={processingBoost === '24h_boost'}
                            >
                                {processingBoost === '24h_boost' ? 'Purchasing...' : '₦1,000'}
                            </button>
                        )}
                    </div>
                    <div className="boost-item">
                        <span className="boost-icon">⭐</span>
                        <h4>Super Swipe</h4>
                        <p className="boost-desc">They get an <strong>instant notification</strong> that someone wants to connect. Your swipe jumps to the top of their queue.</p>
                        {boostData.superSwipeCount > 0 && (
                            <div className="super-swipe-count">
                                {boostData.superSwipeCount} credit{boostData.superSwipeCount !== 1 ? 's' : ''} available
                            </div>
                        )}
                        <button
                            className="btn btn-outline btn-boost"
                            onClick={() => handlePurchaseBoost('super_swipe')}
                            disabled={processingBoost === 'super_swipe'}
                        >
                            {processingBoost === 'super_swipe' ? 'Purchasing...' : '₦500 / credit'}
                        </button>
                    </div>
                </div>
            </div>

            <footer className="support-footer">
                <p>Questions about Premium?
                    <a href="https://wa.me/2349160264415?text=Hi%20👋%20I%20have%20a%20question%20about%20CollegeDate%20Premium" target="_blank" rel="noopener noreferrer">
                        Chat with Support
                    </a>
                </p>
            </footer>
        </div>
    );
}

import { useNavigate } from 'react-router-dom';
import { useState, useEffect } from 'react'; // Add useState, useEffect
import { useAuth } from '../contexts/AuthContext';
import { getWallet } from '../services/paymentService'; // Add wallet service
import AndroidInstallButton from '../components/AndroidInstallButton';
import ProfileCompletion from '../components/ProfileCompletion';
import './Profile.css';
import './Profile_Earnings.css'; // Add this line

export default function Profile() {
