                                </div>
                            </div>
                        )}

                        {userProfile?.intro_prompt && (
                            <div className="vibe-item intro-prompt">
                                <span className="vibe-icon">💬</span>
                                <span className="vibe-text">"{userProfile.intro_prompt}"</span>
                            </div>
                        )}

                        {userProfile?.interests?.length > 0 && (
                            <div className="profile-interests">
                                {userProfile.interests.map((interest, idx) => (
                                    <span key={idx} className="interest-tag">{interest}</span>
                                ))}
                            </div>
                        )}
                    </div>
                )}

                <div className="profile-section">
                    <h3 className="profile-section-title">About Me</h3>
                    <p className="profile-bio">{bio}</p>
                </div>

                <button
                    className="btn btn-primary btn-block"
                    style={{ marginTop: '1.5rem' }}
                    onClick={() => navigate('/profile/edit')}
                >
                    ✏️ Edit Profile
                </button>

                <button
                    className="btn btn-gradient btn-block"
                    style={{ marginTop: '1rem' }}
                    onClick={() => navigate('/premium')}
                >
                    👑 Get Premium
                </button>

                <button
                    className="btn btn-secondary btn-block"
                    style={{ marginTop: '1rem' }}
                    onClick={() => navigate('/leaderboard')}
                >
                    🏆 Leaderboard
                </button>

                <AndroidInstallButton />
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { supabase } from '../lib/supabase';
import { useToast } from '../components/Toast';
import LoadingSpinner from '../components/LoadingSpinner';
import './Referrals.css';

export default function Referrals() {
    const { currentUser, userProfile } = useAuth();
    const { addToast } = useToast();

    const [referrals, setReferrals] = useState([]);
    const [loading, setLoading] = useState(true);
    const [copying, setCopying] = useState(false);

    useEffect(() => {
        if (currentUser) {
            loadReferrals();
        }
    }, [currentUser]);

    async function loadReferrals() {
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('referrals')
                .select(`
                    *,
                    referred:referred_id (
                        full_name,
                        username,
                        avatar_url
                    )
                `)
                .eq('referrer_id', currentUser.id)
                .order('created_at', { ascending: false });

            if (error) throw error;
            setReferrals(data || []);
        } catch (err) {
            console.error('Error loading referrals:', err);
        } finally {
            setLoading(false);
        }
    }

    const handleCopyLink = () => {
        const referralLink = `${window.location.origin}/signup?ref=${userProfile?.referral_code}`;
        navigator.clipboard.writeText(referralLink);
        setCopying(true);
        addToast('Referral link copied to clipboard!', 'success');
        setTimeout(() => setCopying(false), 2000);
    };

    const handleCopyCode = () => {
        navigator.clipboard.writeText(userProfile?.referral_code || '');
        addToast('Referral code copied!', 'success');
    };

    return (
        <div className="referrals-page animated fadeIn">
            <div className="referral-header">
                <h1>Invite & Earn</h1>
                <p>Grow the community and get exclusive rewards for every friend who joins.</p>
            </div>

            <section className="referral-incentives">
                <div className="incentive-card">
                    <div className="incentive-icon">⚡</div>
                    <h3>3 Free Swipes</h3>
                    <p>Instant bonus for every friend who joins CD.</p>
                </div>
                <div className="incentive-card highlight">
                    <div className="incentive-icon">💰</div>
                    <h3>₦3,000 Cash</h3>
                    <p>Milestone reward for every 10 successful referrals.</p>
                </div>
                <div className="incentive-card">
                    <div className="incentive-icon">🎁</div>
                    <h3>Friend's Gift</h3>
                    <p>Your friend gets 20 free swipes to start swiping.</p>
                </div>
            </section>

            <div className="referral-card-container">
                <div className="referral-main-card">
                    <div className="referral-code-section">
                        <span className="label">Your Referral Code</span>
                        <div className="code-display" onClick={handleCopyCode}>
                            {userProfile?.referral_code || '---'}
                        </div>
                    </div>

                    <div className="share-actions">
                        <button className="btn btn-primary share-btn" onClick={handleCopyLink}>
                            {copying ? 'Copied!' : 'Copy Referral Link'}
                        </button>
                    </div>
                </div>

                <div className="referral-stats-grid">
                    <div className="ref-stat">
                        <span className="stat-val">{referrals.length}</span>
                        <span className="stat-name">Invites</span>
                    </div>
                    <div className="ref-stat">
                        <span className="stat-val">{referrals.filter(r => r.status === 'rewarded').length}</span>
                        <span className="stat-name">Rewards</span>
                    </div>
                </div>
            </div>

            <section className="referral-history">
                <h2 className="section-title">Your Friends</h2>
                {loading ? (
                    <div className="loading-container"><LoadingSpinner /></div>
                ) : referrals.length > 0 ? (
                    <div className="referral-list">
                        {referrals.map(ref => (
                            <div key={ref.id} className="referral-item">
                                <img
                                    src={ref.referred?.avatar_url || 'https://via.placeholder.com/40'}
                                    alt="User"
                                    className="ref-avatar"
                                />
                                <div className="ref-info">
                                    <span className="ref-name">{ref.referred?.full_name || 'New Member'}</span>
                                    <span className="ref-date">{new Date(ref.created_at).toLocaleDateString()}</span>
                                </div>
                                <div className={`ref-status status-${ref.status}`}>
                                    {ref.status}
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <div className="no-referrals">
                        <div className="empty-icon">🤝</div>
                        <p>No referrals yet. Start inviting friends!</p>
                    </div>
                )}
            </section>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { supabase } from '../lib/supabase';
import { acceptRequest, declineRequest } from '../services/swipeService';
import { useToast } from '../components/Toast';
import LoadingSpinner from '../components/LoadingSpinner';
import AndroidInstallButton from '../components/AndroidInstallButton';
import './Requests.css';


export default function Requests() {
    const { currentUser } = useAuth();
    const { addToast } = useToast();
    const [requests, setRequests] = useState([]);
    const [loading, setLoading] = useState(true);
    const [actioning, setActioning] = useState(null); // ID of request being processed

    async function fetchRequests() {
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('swipes')
                .select(`
                    *,
                    swiper:profiles!swipes_swiper_id_fkey(*)
                `)
                .eq('swiped_id', currentUser.id)
                .eq('status', 'pending')
                .order('is_priority', { ascending: false })
                .order('created_at', { ascending: false });

            if (error) throw error;
            setRequests(data || []);
        } catch (err) {
            console.error('Error fetching requests:', err);
            addToast('Failed to load requests', 'error');
        } finally {
            setLoading(false);
        }
    }

    useEffect(() => {
        if (!currentUser) return;

        fetchRequests();

        // Subscribe to NEW incoming swipes
        const subscription = supabase
            .channel(`incoming_swipes:${currentUser.id}`)
            .on('postgres_changes', {
                event: 'INSERT',
                schema: 'public',
                table: 'swipes',
                filter: `swiped_id=eq.${currentUser.id}`
            }, (payload) => {
                console.log('New swipe received real-time:', payload.new);
                fetchRequests(); // Refresh list to get swiper profile info
            })
            .on('postgres_changes', {
                event: 'UPDATE',
                schema: 'public',
                table: 'swipes',
                filter: `swiped_id=eq.${currentUser.id}`
            }, (payload) => {
                if (payload.new.status !== 'pending') {
                    setRequests(prev => prev.filter(r => r.id !== payload.new.id));
                }
            })
            .subscribe();

        return () => {
            subscription.unsubscribe();
        };
    }, [currentUser]);

    const handleAccept = async (swipeId) => {
        setActioning(swipeId);
        try {
            const { data, error } = await acceptRequest(swipeId);
            if (error) throw error;
            if (data && !data.success) throw new Error(data.error || 'Failed to accept');

            addToast('Request accepted! Chat unlocked.', 'success');
            setRequests(prev => prev.filter(r => r.id !== swipeId));
            setTimeout(() => navigate('/chat'), 1500);
        } catch (err) {
            addToast(err.message, 'error');
        } finally {
            setActioning(null);
        }
    };

    const handleDecline = async (swipeId) => {
        setActioning(swipeId);
        try {
            const { success, error } = await declineRequest(swipeId);
            if (!success) throw new Error(error);

            addToast('Request declined.', 'info');
            setRequests(prev => prev.filter(r => r.id !== swipeId));
        } catch (err) {
            addToast(err.message, 'error');
        } finally {
            setActioning(null);
        }
    };

    if (loading) return <LoadingSpinner fullScreen text="Loading requests..." />;

    return (
        <div className="requests-page animated fadeIn">
            <div className="requests-header">
                <h1>Connection Requests</h1>
                <p>Manage people who want to vibe with you.</p>
                <AndroidInstallButton />
            </div>

            {userProfile?.completion_score < 100 && (
                <div className="completion-nudge-card card-glow" onClick={() => navigate('/profile/edit')}>
                    <div className="nudge-icon">⚠️</div>
                    <div className="nudge-content">
                        <h3>Your profile is {userProfile.completion_score}% complete</h3>
                        <p>Complete it to appear more in discovery.</p>
                    </div>
                </div>
            )}

            {requests.length > 0 ? (
                <div className="requests-grid">
                    {requests.map(req => (
                        <div key={req.id} className={`request-card ${req.is_priority ? 'priority' : ''}`}>
                            {req.is_priority && (
                                <div className="priority-badge">💎 PREMIUM</div>
                            )}
                            <div className="request-user">
                                <div className="user-avatar-small">
                                    {req.swiper.avatar_url ? (
                                        <img src={req.swiper.avatar_url} alt={req.swiper.full_name} />
                                    ) : (
                                        <div className="avatar-placeholder">{req.swiper.full_name?.charAt(0)}</div>
                                    )}
                                </div>
                                <div className="user-details">
                                    <h3>{req.swiper.full_name}</h3>
                                    <p>{req.swiper.university}</p>
                                </div>
                            </div>

                            {req.message_teaser && (
                                <div className="request-teaser">
                                    <span className="teaser-quote">“</span>
                                    <p>{req.message_teaser}</p>
                                </div>
                            )}

                            <div className="request-actions">
                                <button
                                    className="btn-accept"
                                    disabled={actioning === req.id}
                                    onClick={() => handleAccept(req.id)}
                                >
                                    {actioning === req.id ? '...' : 'Accept'}
                                </button>
                                <button
                                    className="btn-decline"
                                    disabled={actioning === req.id}
                                    onClick={() => handleDecline(req.id)}
                                >
                                    Decline
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="empty-requests">
                    <div className="empty-icon">💌</div>
                    <h2>No pending requests</h2>
                    <p>When someone swipes right on you, they'll appear here!</p>
                </div>
            )}
        </div>
    );
}

