import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { getUserSettings, updateUserSettings } from '../services/notificationService';
import { useToast } from '../components/Toast';
import LoadingSpinner from '../components/LoadingSpinner';
import AndroidInstallButton from '../components/AndroidInstallButton';
import './Settings.css';

export default function Settings() {
    const { currentUser, userProfile, logout } = useAuth();
    const { addToast } = useToast();
    const navigate = useNavigate();
    const [settings, setSettings] = useState(null);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        if (currentUser) {
            loadSettings();
        }
    }, [currentUser]);

    async function loadSettings() {
        setLoading(true);
        const { data, error } = await getUserSettings(currentUser.id);
        if (error) {
            addToast('Failed to load settings', 'error');
            // Provide sensible defaults so the page still renders
            setSettings({
                match_notifications: true,
                email_notifications: true,
                push_notifications: true,
                show_online_status: true,
                incognito_mode: false
            });
        } else {
            // If data is null (no profile row), use defaults
            setSettings(data || {
                match_notifications: true,
                email_notifications: true,
                push_notifications: true,
                show_online_status: true,
                incognito_mode: false
            });
        }
        setLoading(false);
    }

    const handleToggle = async (key) => {
        if (!settings) return;

        const newSettings = { ...settings, [key]: !settings[key] };
        setSettings(newSettings); // Optimistic update

        setSaving(true);
        const { error } = await updateUserSettings(currentUser.id, { [key]: !settings[key] });
        if (error) {
            addToast('Failed to save setting', 'error');
            setSettings(settings); // Revert
        }
        setSaving(false);
    };

    if (loading) return <LoadingSpinner fullScreen text="Loading preferences..." />;

    return (
        <div className="settings-page animated fadeIn">
            <div className="settings-header">
                <h1>Settings</h1>
                <p>Manage your account preferences and notifications.</p>
            </div>

            <div className="settings-section">
                <h2 className="section-title">Account</h2>
                <div className="settings-list">
                    <div className="settings-item status-item">
                        <div className="item-info">
                            <h3>Profile Visibility Status</h3>
                            <p>Current reach in discovery</p>
                        </div>
                        <span className={`status-badge ${(userProfile?.completion_score || 0) < 60 ? 'limited' : 'optimised'}`}>
                            {(userProfile?.completion_score || 0) < 60 ? 'Limited' : 'Optimised'}
                        </span>
                    </div>
                    <div className="settings-item feature-link" onClick={() => navigate('/premium')}>
                        <div className="item-info">
                            <h3>👑 Get Premium</h3>
                            <p>Unlock Super Swipes and more visibility.</p>
                        </div>
                        <span className="chevron">›</span>
                    </div>
                    <div className="settings-item feature-link" onClick={() => navigate('/referrals')}>
                        <div className="item-info">
                            <h3>🎁 Referrals</h3>
                            <p>Invite friends and earn rewards.</p>
                        </div>
                        <span className="chevron">›</span>
                    </div>
                    <AndroidInstallButton />
                </div>
            </div>

            <div className="settings-section">
                <h2 className="section-title">Notifications</h2>
                <div className="settings-list">
                    <div className="settings-item">
                        <div className="item-info">
                            <h3>Match Alerts</h3>
                            <p>Get notified when you get a new connection.</p>
                        </div>
                        <label className="switch">
                            <input
                                type="checkbox"
                                checked={settings?.match_notifications}
                                onChange={() => handleToggle('match_notifications')}
                            />
                            <span className="slider round"></span>
                        </label>
                    </div>

                    <div className="settings-item">
                        <div className="item-info">
                            <h3>Email Notifications</h3>
                            <p>Receive weekly digests and account updates.</p>
                        </div>
                        <label className="switch">
                            <input
                                type="checkbox"
                                checked={settings?.email_notifications}
                                onChange={() => handleToggle('email_notifications')}
                            />
                            <span className="slider round"></span>
                        </label>
                    </div>

                    <div className="settings-item">
                        <div className="item-info">
                            <h3>Push Notifications</h3>
                            <p>Get instant alerts on your device.</p>
                        </div>
                        <label className="switch">
                            <input
                                type="checkbox"
                                checked={settings?.push_notifications}
                                onChange={() => handleToggle('push_notifications')}
                            />
                            <span className="slider round"></span>
                        </label>
                    </div>
                </div>
            </div>

            <div className="settings-section">
                <h2 className="section-title">Privacy</h2>
                <div className="settings-list">
                    <div className="settings-item">
                        <div className="item-info">
                            <h3>Show Online Status</h3>
                            <p>Let others see when you are active.</p>
                        </div>
                        <label className="switch">
                            <input
                                type="checkbox"
                                checked={settings?.show_online_status}
                                onChange={() => handleToggle('show_online_status')}
                            />
                            <span className="slider round"></span>
                        </label>
                    </div>

                    <div className="settings-item">
                        <div className="item-info">
                            <h3>Incognito Mode</h3>
                            <p>Hide your profile from Discovery temporarily.</p>
                        </div>
                        <label className="switch">
                            <input
                                type="checkbox"
                                checked={settings?.incognito_mode}
                                onChange={() => handleToggle('incognito_mode')}
                            />
                            <span className="slider round"></span>
                        </label>
                    </div>
                </div>
            </div>

            <div className="settings-section">
                <h2 className="section-title">Support</h2>
                <div className="settings-list">
                    <a
                        href="https://wa.me/2349160264415?text=Hi%20👋%20I%20need%20help%20with%20CollegeDate"
                        target="_blank"
                        rel="noopener noreferrer"
                        className="settings-item feature-link support-link"
                    >
                        <div className="item-info">
                            <h3>💬 Contact Support</h3>
                            <p>Chat with us on WhatsApp for fast help.</p>
                        </div>
                        <span className="chevron">›</span>
                    </a>
                    <div className="settings-item">
                        <div className="item-info">
                            <h3>📧 Email Us</h3>
                            <p>info@thecollegedate.com</p>
                        </div>
                    </div>
                </div>
            </div>

            <div className="settings-section">
                <h2 className="section-title">Account</h2>
                <div className="settings-list">
                    <button className="settings-action-btn logout" onClick={logout}>
                        Log Out
                    </button>
                    <button className="settings-action-btn delete">
                        Deactivate Account
                    </button>
                </div>
            </div>

            {saving && <div className="saving-indicator">Saving...</div>}
        </div>
    );
}

import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { supabase } from '../lib/supabase';
import { useToast } from '../components/Toast';
import './Auth.css';

export default function Signup() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [role, setRole] = useState(''); // 'Male' or 'Female'
    const [isLoading, setIsLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);

    const { signup, loginWithGoogle, error, clearError } = useAuth();
    const { success, error: showError } = useToast();
    const navigate = useNavigate();

    // Extract referral code from URL
    const [referralCode, setReferralCode] = useState(() => {
        const params = new URLSearchParams(window.location.search);
        return params.get('ref') || '';
    });

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!email || !password || !confirmPassword || !role) {
            showError('Please fill in all fields and select your role');
            return;
        }

        if (password.length < 6) {
            showError('Password must be at least 6 characters');
            return;
        }

        if (password !== confirmPassword) {
            showError('Passwords do not match');
            return;
        }

        setIsLoading(true);
        clearError();

        let referrerId = null;
        if (referralCode) {
            const { data: referrerData, error: refError } = await supabase
                .from('profiles')
                .select('id')
                .eq('referral_code', referralCode)
                .single();

            if (!refError && referrerData) {
                referrerId = referrerData.id;
            }
        }

        const { data, error: signupErr } = await signup(email, password, {
            referred_by: referrerId,
            role: role
        });

        if (!signupErr && (data?.user) && referrerId) {
            // Create a record in the referrals table
            await supabase.from('referrals').insert({
                referrer_id: referrerId,
                referred_id: data.user.id,
                status: 'completed'
            });
        }

        setIsLoading(false);

        if (signupErr) {
            showError(signupErr);
        } else if (data?.session) {
            success('Account created! Welcome to College Date 💕');
            navigate('/mini-profile-setup', { replace: true });
        }
    };

    const handleGoogleLogin = async () => {
        setIsLoading(true);
        const { error: err } = await loginWithGoogle();
        if (err) {
            showError(err);
            setIsLoading(false);
        }
    };


    return (
        <div className="auth-page">
            <div className="auth-bg-shapes">
                <div className="auth-shape auth-shape-1"></div>
                <div className="auth-shape auth-shape-2"></div>
                <div className="auth-shape auth-shape-3"></div>
            </div>

            <div className="auth-container">
                <div className="auth-card">
                    <div className="auth-header">
                        <span className="auth-logo">💕</span>
                        <h1 className="auth-title">Join College Date</h1>
                        <p className="auth-subtitle">Create your account and start meeting people</p>
                    </div>

                    {error && (
                        <div className="auth-error">
                            <span>⚠️</span> {error}
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="auth-form">
                        <div className="form-group">
                            <label htmlFor="email" className="form-label">Email</label>
                            <div className="input-wrapper">
                                <span className="input-icon">📧</span>
                                <input
                                    id="email"
                                    type="email"
                                    className="form-input"
                                    placeholder="you@university.edu"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    disabled={isLoading}
                                    autoComplete="email"
                                />
                            </div>
                        </div>

                        <div className="form-group">
                            <label className="form-label">I am a...</label>
                            <div className="role-selection">
                                <button
                                    type="button"
                                    className={`role-btn ${role === 'Male' ? 'active' : ''}`}
                                    onClick={() => setRole('Male')}
                                    disabled={isLoading}
                                >
                                    🙋‍♂️ Guy
                                </button>
                                <button
                                    type="button"
                                    className={`role-btn ${role === 'Female' ? 'active' : ''}`}
                                    onClick={() => setRole('Female')}
                                    disabled={isLoading}
                                >
                                    🙋‍♀️ Lady
                                </button>
                            </div>
                        </div>

                        <div className="form-group">
                            <label htmlFor="password" className="form-label">Password</label>
                            <div className="input-wrapper">
                                <span className="input-icon">🔒</span>
                                <input
                                    id="password"
                                    type={showPassword ? 'text' : 'password'}
                                    className="form-input"
                                    placeholder="At least 6 characters"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    disabled={isLoading}
                                    autoComplete="new-password"
                                />
                                <button
                                    type="button"
                                    className="input-toggle"
                                    onClick={() => setShowPassword(!showPassword)}
                                    tabIndex={-1}
                                >
                                    {showPassword ? '🙈' : '👁️'}
                                </button>
                            </div>
                        </div>

                        <div className="form-group">
                            <label htmlFor="confirmPassword" className="form-label">Confirm Password</label>
                            <div className="input-wrapper">
                                <span className="input-icon">🔒</span>
                                <input
                                    id="confirmPassword"
                                    type={showPassword ? 'text' : 'password'}
                                    className="form-input"
                                    placeholder="Confirm your password"
                                    value={confirmPassword}
                                    onChange={(e) => setConfirmPassword(e.target.value)}
                                    disabled={isLoading}
                                    autoComplete="new-password"
                                />
                            </div>
                        </div>

                        <button type="submit" className="btn btn-primary btn-block" disabled={isLoading}>
                            {isLoading ? (
                                <span className="btn-loading">
                                    <span className="btn-spinner"></span>
                                    Creating account...
                                </span>
                            ) : (
                                'Create Account'
                            )}
                        </button>
                    </form>

                    <div className="auth-divider">
                        <span>or continue with</span>
                    </div>

                    <div className="social-buttons">
                        <button className="btn btn-social btn-google" onClick={handleGoogleLogin} disabled={isLoading}>
                            <svg viewBox="0 0 24 24" width="20" height="20">
                                <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 01-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" />
                                <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
                                <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
                                <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
                            </svg>
                            Google
                        </button>

                    </div>

                    <p className="auth-footer">
                        Already have an account? <Link to="/login" className="auth-link">Sign In</Link>
                    </p>
                </div>
            </div>
        </div>
    );
}

