import { useState, useEffect, useRef } from 'react';
import { useLocation } from 'react-router-dom'; // Add useLocation
import { useAuth } from '../contexts/AuthContext';
import { useToast } from '../components/Toast';
import { getReceivedSnaps, sendSnap, openSnap } from '../services/snapService';
import { getConversations } from '../services/chatService'; // To pick recipients
import LoadingSpinner from '../components/LoadingSpinner';
import './Snapshots.css'; // Re-use styling

export default function Snap() {
    const { currentUser } = useAuth();
    const { addToast } = useToast();

    const location = useLocation(); // Get location

    // State
    const [viewMode, setViewMode] = useState(location.state?.recipient ? 'camera' : 'inbox'); // Default to camera if recipient passed
    const [snaps, setSnaps] = useState([]);
    const [loading, setLoading] = useState(true);
    const [friends, setFriends] = useState([]);

    // Camera/Upload State
    const [selectedFile, setSelectedFile] = useState(null);
    const [previewUrl, setPreviewUrl] = useState(null);
    const [selectedFriend, setSelectedFriend] = useState(location.state?.recipient ? { other_user: location.state.recipient } : null);
    const [sending, setSending] = useState(false);

    // Viewing State
    const [activeSnap, setActiveSnap] = useState(null);
    const [timeLeft, setTimeLeft] = useState(10);

    const fileInputRef = useRef(null);

    useEffect(() => {
        if (currentUser) {
            loadInbox();
            loadFriends();
        }
    }, [currentUser]);

    // Timer for active snap
    useEffect(() => {
        let timer;
        if (activeSnap && timeLeft > 0) {
            timer = setTimeout(() => setTimeLeft(prev => prev - 1), 1000);
        } else if (activeSnap && timeLeft === 0) {
            handleCloseSnap();
        }
        return () => clearTimeout(timer);
    }, [activeSnap, timeLeft]);

    const loadInbox = async () => {
        setLoading(true);
        const { data } = await getReceivedSnaps(currentUser.id);
        setSnaps(data || []);
        setLoading(false);
    };

    const loadFriends = async () => {
        const { data } = await getConversations(currentUser.id);
        setFriends(data || []);
    };

    const handleFileSelect = (e) => {
        const file = e.target.files[0];
        if (file) {
            setSelectedFile(file);
            setPreviewUrl(URL.createObjectURL(file));
        }
    };

    const handleSend = async () => {
        if (!selectedFile || !selectedFriend) return;

        setSending(true);
        const { error } = await sendSnap(currentUser.id, selectedFriend.other_user.id, selectedFile);

        if (error) {
            addToast('Failed to send snap', 'error');
        } else {
            addToast('Snap sent!', 'success');
            // Reset
            setSelectedFile(null);
            setPreviewUrl(null);
            setSelectedFriend(null);
            setViewMode('inbox');
        }
        setSending(false);
    };

    const handleOpenSnap = (snap) => {
        setActiveSnap(snap);
        setTimeLeft(10); // 10 seconds to view
    };

    const handleCloseSnap = async () => {
        if (!activeSnap) return;

        // Mark as opened in background
        await openSnap(activeSnap.id);

        // Remove from list
        setSnaps(prev => prev.filter(s => s.id !== activeSnap.id));
        setActiveSnap(null);
    };

    if (loading) return <LoadingSpinner fullScreen />;

    return (
        <div className="snap-page">
            {/* View Snap Overlay */}
            {activeSnap && (
                <div className="snap-viewer-overlay" onClick={handleCloseSnap}>
                    <div className="snap-timer-bar">
                        <div className="timer-fill" style={{ width: `${(timeLeft / 10) * 100}%` }}></div>
                    </div>
                    <img src={activeSnap.media_url} alt="Snap" className="snap-viewer-media" />
                    <div className="snap-sender-info">
                        <img src={activeSnap.sender?.avatar_url} alt="Sender" />
                        <span>{activeSnap.sender?.full_name}</span>
                    </div>
                </div>
            )}

            <header className="snap-header">
                <h1>👻 Snap</h1>
                <div className="snap-actions">
                    <button
                        className={`btn-snap-action ${viewMode === 'inbox' ? 'active' : ''}`}
                        onClick={() => setViewMode('inbox')}
                    >
                        📥 {snaps.length > 0 && <span className="badge">{snaps.length}</span>}
                    </button>
                    <button
                        className={`btn-snap-action ${viewMode === 'camera' ? 'active' : ''}`}
                        onClick={() => setViewMode('camera')}
                    >
                        📷
                    </button>
                </div>
            </header>

            <div className="snap-content">
                {viewMode === 'inbox' ? (
                    <div className="snap-inbox">
                        {snaps.length === 0 ? (
                            <div className="empty-state">
                                <div className="empty-icon">📮</div>
                                <p>No new snaps.</p>
                                <button className="btn-primary" onClick={() => setViewMode('camera')}>
                                    Send a Snap
                                </button>
                            </div>
                        ) : (
                            <ul className="snap-list">
                                {snaps.map(snap => (
                                    <li key={snap.id} className="snap-item" onClick={() => handleOpenSnap(snap)}>
                                        <div className="snap-avatar-ring">
                                            <img src={snap.sender?.avatar_url || 'https://via.placeholder.com/40'} alt="Sender" />
                                        </div>
                                        <div className="snap-info">
                                            <span className="snap-sender">{snap.sender?.full_name}</span>
                                            <span className="snap-time">
                                                New Snap • {new Date(snap.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                            </span>
                                        </div>
                                        <div className="snap-indicator">🔴</div>
                                    </li>
                                ))}
                            </ul>
                        )}
                    </div>
                ) : (
                    <div className="snap-compose">
                        {!previewUrl ? (
                            <div className="camera-placeholder" onClick={() => fileInputRef.current?.click()}>
                                <input
                                    type="file"
                                    hidden
                                    ref={fileInputRef}
                                    accept="image/*"
                                    capture="environment"
                                    onChange={handleFileSelect}
                                />
                                <div className="camera-icon">📸</div>
                                <p>Tap to take a photo or upload</p>
                            </div>
                        ) : (
                            <div className="snap-preview-container">
                                <img src={previewUrl} alt="Preview" className="snap-preview" />
                                <button className="btn-close-preview" onClick={() => {
                                    setPreviewUrl(null);
                                    setSelectedFile(null);
                                }}>&times;</button>

                                <div className="snap-send-controls">
                                    <select
                                        className="friend-selector"
                                        value={selectedFriend?.id || ''}
                                        onChange={(e) => {
                                            const friend = friends.find(f => f.id === e.target.value);
                                            setSelectedFriend(friend);
                                        }}
                                    >
                                        <option value="">Select Recipient...</option>
                                        {friends.map(f => (
                                            <option key={f.id} value={f.id}>{f.other_user?.full_name}</option>
                                        ))}
                                    </select>

                                    <button
                                        className="btn-send-snap"
                                        disabled={!selectedFriend || sending}
                                        onClick={handleSend}
                                    >
                                        {sending ? 'Sending...' : 'Send ➤'}
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { getSnapshots, uploadSnapshotMedia, createSnapshot, likeSnapshot, getHiddenContentCounts } from '../services/snapshotService';
import { useToast } from '../components/Toast';
import LoadingSpinner from '../components/LoadingSpinner';
import './Snapshots.css';

export default function Snapshots() {
    const { currentUser } = useAuth();
    const { addToast } = useToast();
    const fileInputRef = useRef(null);

    const [snapshots, setSnapshots] = useState([]);
    const [hiddenCount, setHiddenCount] = useState(0);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);

    // Upload state
    const [uploadFile, setUploadFile] = useState(null);
    const [preview, setPreview] = useState(null);
    const [description, setDescription] = useState('');
    const [uploading, setUploading] = useState(false);

    const loadSnapshots = async () => {
        setLoading(true);
        // 1. Get visible snapshots
        const { data, error } = await getSnapshots();
        if (error) {
            console.error('Failed to load snapshots:', error);
        } else {
            setSnapshots(data || []);
        }

        // 2. Get hidden counts
        if (currentUser) {
            const { data: counts } = await getHiddenContentCounts(currentUser.id);
            setHiddenCount(counts?.hidden_snapshots || 0);
        }

        setLoading(false);
    };

    useEffect(() => {
        loadSnapshots();
    }, []);

    const handleFileChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            setUploadFile(file);
            setPreview(URL.createObjectURL(file));
            setShowModal(true);
        }
    };

    const handleUpload = async () => {
        if (!uploadFile) return;
        setUploading(true);
        try {
            const { url, error: uploadError } = await uploadSnapshotMedia(uploadFile, currentUser.id);
            if (uploadError) throw new Error('Failed to upload image');

            const { error: createError } = await createSnapshot(currentUser.id, url, description);
            if (createError) throw new Error('Failed to create snapshot');

            addToast('Snapshot shared successfully!', 'success');
            closeModal();
            loadSnapshots();
        } catch (err) {
            addToast(err.message, 'error');
        } finally {
            setUploading(false);
        }
    };

    const closeModal = () => {
        setShowModal(false);
        setUploadFile(null);
        setPreview(null);
        setDescription('');
    };

    const handleLike = async (id) => {
        if (!currentUser) return;

        // Optimistic update
        setSnapshots(prev => prev.map(s =>
            s.id === id ? { ...s, likes_count: (s.likes_count || 0) + 1 } : s
        ));

        const { error } = await likeSnapshot(id, currentUser.id);
        if (error) {
            console.error('Like failed:', error);
        }
    };

    return (
        <div className="snapshots-page">
            <header className="snapshots-header">
                <h1>Campus Snapshots</h1>
                <button
                    className="btn-add-snapshot"
                    onClick={() => fileInputRef.current?.click()}
                >
                    + Add Snapshot
                </button>
                <input
                    type="file"
                    ref={fileInputRef}
                    onChange={handleFileChange}
                    accept="image/*"
                    hidden
                />
            </header>

            {loading ? (
                <LoadingSpinner />
            ) : snapshots.length === 0 ? (
                <div className="no-snapshots">
                    <p>No snapshots yet. Be the first to post! 📸</p>
                </div>
            ) : (
                <div className="snapshots-grid">
                    {snapshots.map(snapshot => (
                        <div key={snapshot.id} className="snapshot-card animated fadeIn">
                            {/* ... existing snapshot card ... */}
                            <div className="snapshot-image-wrapper">
                                <img src={snapshot.media_url} alt="Snapshot" />
                                <div className="snapshot-overlay">
                                    <div className="snapshot-user">
                                        <img
                                            src={snapshot.profiles?.avatar_url || 'https://via.placeholder.com/30'}
                                            alt={snapshot.profiles?.full_name}
                                        />
                                        <span>{snapshot.profiles?.full_name}</span>
                                    </div>
                                    <button
                                        className="btn-like-snapshot"
                                        onClick={() => handleLike(snapshot.id)}
                                    >
                                        ❤️ {snapshot.likes_count || 0}
                                    </button>
                                </div>
                            </div>
                            {snapshot.description && (
                                <p className="snapshot-desc">{snapshot.description}</p>
                            )}
                        </div>
                    ))}

                    {hiddenCount > 0 && (
                        <div className="snapshot-card locked animated pulse infinite-once">
                            <div className="locked-image-placeholder">
                                <div className="locked-overlay-content">
                                    <span className="lock-emoji">🔒</span>
                                    <span className="lock-count">{hiddenCount} Locked Snapshots</span>
                                    <button className="btn-grid-unlock" onClick={() => window.location.href = '/discover'}>
                                        Unlock in Discover
                                    </button>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            )}

            {/* Upload Modal */}
            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content animated zoomIn">
                        <h2>New Snapshot</h2>
                        {preview && <img src={preview} alt="Preview" className="upload-preview" />}
                        <textarea
                            placeholder="Add a caption..."
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            className="snapshot-input"
                        />
                        <div className="modal-actions">
                            <button onClick={closeModal} className="btn-cancel" disabled={uploading}>Cancel</button>
                            <button onClick={handleUpload} className="btn-confirm" disabled={uploading}>
                                {uploading ? <LoadingSpinner size="small" color="white" /> : 'Post'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

