import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { getRecentStatuses, getHiddenContentCounts } from '../services/statusService';
import StatusInput from '../components/StatusInput';
import StatusFeed from '../components/StatusFeed';
import { useToast } from '../components/Toast';
import './StatusUpdates.css';

export default function StatusUpdates() {
    const { currentUser } = useAuth();
    const { addToast } = useToast();

    const [statuses, setStatuses] = useState([]);
    const [hiddenCount, setHiddenCount] = useState(0);
    const [loading, setLoading] = useState(true);

    const loadStatuses = useCallback(async () => {
        setLoading(true);
        // 1. Load visible statuses
        const { data, error } = await getRecentStatuses();
        if (error) {
            console.error('Failed to load statuses:', error);
        } else {
            setStatuses(data || []);
        }

        // 2. Load hidden counts for FOMO
        if (currentUser) {
            const { data: counts } = await getHiddenContentCounts(currentUser.id);
            setHiddenCount(counts?.hidden_statuses || 0);
        }

        setLoading(false);
    }, [currentUser]);

    useEffect(() => {
        loadStatuses();
    }, [loadStatuses]);

    const handleStatusPosted = () => {
        loadStatuses();
    };

    return (
        <div className="status-page">
            <div className="status-header-section">
                <h1>Status Updates</h1>
                <p>Share moments that disappear after 24 hours.</p>
            </div>

            <div className="status-content-wrapper">
                <StatusInput onStatusPosted={handleStatusPosted} />

                <h2 className="section-title">Recent Updates</h2>
                <StatusFeed statuses={statuses} loading={loading} hiddenCount={hiddenCount} />
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { supabase } from '../lib/supabase';
import { useNavigate } from 'react-router-dom';
import LoadingSpinner from '../components/LoadingSpinner';
import './Viewers.css';

export default function Viewers() {
    const { currentUser, userProfile } = useAuth();
    const [viewers, setViewers] = useState([]);
    const [loading, setLoading] = useState(true);
    const isPremium = userProfile?.plan_type === 'Premium';
    const navigate = useNavigate();

    useEffect(() => {
        if (currentUser) {
            fetchViewers();
        }
    }, [currentUser]);

    async function fetchViewers() {
        try {
            setLoading(true);
            // Fetch profile views with viewer profile info
            const { data, error } = await supabase
                .from('profile_views')
                .select(`
                    id,
                    created_at,
                    viewer:profiles!viewer_id (
                        id,
                        full_name,
                        avatar_url,
                        university,
                        last_active
                    )
                `)
                .eq('profile_owner_id', currentUser.id)
                .order('created_at', { ascending: false })
                .limit(20);

            if (error) throw error;
            setViewers(data || []);
        } catch (err) {
            console.error('Error fetching viewers:', err);
        } finally {
            setLoading(false);
        }
    }

    if (loading) return <LoadingSpinner fullScreen />;

    return (
        <div className="viewers-page">
            <header className="viewers-header">
                <button className="back-btn" onClick={() => navigate(-1)}>←</button>
                <h1>Who Viewed You</h1>
            </header>

            <div className="viewers-list">
                {viewers.length === 0 ? (
                    <div className="no-viewers">
                        <div className="no-viewers-icon">🕶️</div>
                        <h3>No views yet today</h3>
                        <p>Try boosting your profile to get more eyes!</p>
                    </div>
                ) : (
                    viewers.map((item) => (
                        <div key={item.id} className="viewer-card">
                            <div className={`viewer-avatar ${!isPremium ? 'blurred' : ''}`}>
                                <img
                                    src={item.viewer?.avatar_url || '/default-avatar.png'}
                                    alt="Viewer"
                                />
                            </div>
                            <div className="viewer-info">
                                <h3 className={!isPremium ? 'blurred-text' : ''}>
                                    {isPremium ? item.viewer?.full_name : '•••••••• •••••'}
                                </h3>
                                <p>{new Date(item.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                            </div>
                            {!isPremium && <div className="lock-icon">🔒</div>}
                        </div>
                    ))
                )}
            </div>

            {!isPremium && viewers.length > 0 && (
                <div className="premium-upsell-sticky">
                    <h3>Unlock {viewers.length} Secret Admirers!</h3>
                    <p>See exactly who’s interested in you.</p>
                    <button className="btn-unlock-premium" onClick={() => navigate('/premium')}>
                        Get Premium Now
                    </button>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import {
    getWallet,
    getTransactions,
    createTransaction,
    completeTransaction,
    initializePaystack,
    getPayoutDetails,
    updatePayoutDetails
} from '../services/paymentService';
import { useToast } from '../components/Toast';
import LoadingSpinner from '../components/LoadingSpinner';
import { supabase } from '../lib/supabase';
import './Wallet.css';

export default function Wallet() {
    const { currentUser, userProfile } = useAuth();
    const { addToast } = useToast();

    const [wallet, setWallet] = useState(null);
    const [transactions, setTransactions] = useState([]);
    const [loading, setLoading] = useState(true);
    const [fundingAmount, setFundingAmount] = useState('2000');
    const [withdrawalAmount, setWithdrawalAmount] = useState('');
    const [isProcessing, setIsProcessing] = useState(false);

    // Payout Details State
    const [payoutDetails, setPayoutDetails] = useState({
        bank_name: '',
        account_number: '',
        account_name: '',
        paypal_email: '',
        preferred_method: 'bank'
    });

    useEffect(() => {
        if (!currentUser) return;

        loadWalletData();

        // Subscribe to real-time wallet updates
        const walletSubscription = supabase
            .channel(`wallet_updates:${currentUser.id}`)
            .on(
                'postgres_changes',
                {
                    event: 'UPDATE',
                    schema: 'public',
                    table: 'wallets',
                    filter: `user_id=eq.${currentUser.id}`
                },
                (payload) => {
                    console.log('💰 Wallet updated via Realtime:', payload.new);
                    setWallet(payload.new);
                    // Also reload transactions to show the new entry
                    loadWalletData();
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(walletSubscription);
        };
    }, [currentUser]);

    async function loadWalletData() {
        setLoading(true);
        try {
            const { data: walletData, error: walletError } = await getWallet(currentUser.id);
            if (walletError) throw walletError;
            setWallet(walletData);

            // Only load transactions if wallet has a real DB id
            if (walletData && walletData.id) {
                const { data: txData, error: txError } = await getTransactions(walletData.id);
                if (txError) throw txError;
                setTransactions(txData || []);
            }

            // Load Payout Details
            try {
                const { data: payoutData } = await getPayoutDetails(currentUser.id);
                if (payoutData) {
                    setPayoutDetails(payoutData);
                }
            } catch (payoutErr) {
                // Payout details are optional, don't crash
                console.warn('Could not load payout details:', payoutErr);
            }
        } catch (err) {
            console.error('Error loading wallet data:', err);
            // Still set a default wallet so the page renders
            setWallet({
                id: null,
                user_id: currentUser.id,
                available_balance: 0,
                pending_balance: 0,
                total_earned: 0,
            });
        } finally {
            setLoading(false);
        }
    }

    const handleFunding = async (e) => {
        e.preventDefault();
        const amount = parseFloat(fundingAmount);

        if (isNaN(amount) || amount < 2000) {
            addToast('Minimum deposit is ₦2,000', 'warning');
            return;
        }

        setIsProcessing(true);

        if (!wallet || !wallet.id) {
            addToast('Wallet not initialized yet. Please complete your profile or contact support.', 'error');
            setIsProcessing(false);
            return;
        }

        try {
            // 1. Create a pending transaction record
            const { data: tx, error: txError } = await createTransaction({
                wallet_id: wallet.id,
                user_id: currentUser.id,
                type: 'deposit',
                amount: amount,
                status: 'pending',
                description: 'Wallet Funding via Flutterwave'
            });

            if (txError) throw txError;

            // 2. Initialize Paystack
            initializePaystack({
                public_key: import.meta.env.VITE_PAYSTACK_PUBLIC_KEY,
                reference: `CD-TX-${tx.id}`,
                amount: amount,
                email: currentUser.email,
                metadata: {
                    user_id: currentUser.id,
                    tx_id: tx.id,
                    type: 'deposit'
                },
                onSuccess: async (response) => {
                    const { error: completeError } = await completeTransaction(
                        tx.id,
                        'success',
                        response.reference,
                        response
                    );

                    if (completeError) {
                        addToast('Payment successful but wallet update failed.', 'error');
                    } else {
                        addToast('Wallet funded successfully!', 'success');
                        loadWalletData();
                        setIsProcessing(false);
                    }
                },
                onCancel: () => {
                    setIsProcessing(false);
                }
            });

        } catch (err) {
            console.error('Funding error:', err);
            addToast(err.message, 'error');
            setIsProcessing(false);
        }
    };

    const handleWithdrawal = async (e) => {
        e.preventDefault();
        const amount = parseFloat(withdrawalAmount);
        const type = 'swipe_earnings'; // Default for ladies

        // Validation
        if (isNaN(amount) || amount < 15000) {
            addToast('Minimum withdrawal for earnings is ₦15,000', 'warning');
            return;
        }

        if (!wallet || !wallet.id) {
            addToast('Wallet not initialized yet. Please complete your profile or contact support.', 'error');
            return;
        }

        if (amount > (wallet?.available_balance || 0)) {
            addToast('Insufficient balance', 'error');
            return;
        }

        setIsProcessing(true);
        try {
            const { error: withdrawalErr } = await supabase
                .from('withdrawals')
                .insert({
                    user_id: currentUser.id,
                    amount: amount,
                    type: type,
                    status: 'pending',
                    bank_details: { bank: 'User Bank', account: '1234567890' } // Placeholder
                });

            if (withdrawalErr) throw withdrawalErr;

            // Deduct from available, move to pending
            const { error: updateErr } = await supabase
                .from('wallets')
                .update({
                    available_balance: wallet.available_balance - amount,
                    pending_balance: (wallet.pending_balance || 0) + amount,
                    updated_at: new Date().toISOString()
                })
                .eq('id', wallet.id);

            if (updateErr) throw updateErr;

            addToast('Withdrawal request submitted! Payouts are processed weekly.', 'success');
            loadWalletData();
            setWithdrawalAmount('');
        } catch (err) {
            addToast(err.message, 'error');
        } finally {
            setIsProcessing(false);
        }
    };

    const handleSavePayout = async (e) => {
        e.preventDefault();
        setIsProcessing(true);
        try {
            const { error } = await updatePayoutDetails(currentUser.id, payoutDetails);
            if (error) throw error;
            addToast('Payout details saved successfully!', 'success');
        } catch (err) {
            addToast(err.message, 'error');
        } finally {
            setIsProcessing(false);
        }
    };

    if (loading) return <LoadingSpinner fullScreen />;

    const isLady = userProfile?.role === 'Female';

    return (
        <div className="wallet-page animated fadeIn">
            <div className="wallet-header">
                <h1>{isLady ? 'Earnings Dashboard' : 'My Wallet'}</h1>
                <p>{isLady ? 'Track your swipes and request payouts.' : 'Fund your wallet and keep swiping.'}</p>
                <a href="https://wa.me/2349160264415?text=Hi%20👋%20I%20need%20help%20with%20my%20wallet/payout"
                    target="_blank"
                    rel="noopener noreferrer"
                    className="wallet-support-link">
                    Need help? Chat with Support
                </a>
            </div>

            <div className="wallet-overview-grid">
                <div className="balance-card">
                    <span className="balance-label">{isLady ? 'Available for Withdrawal' : 'Available Balance'}</span>
                    <h2 className="balance-amount">
                        ₦{parseFloat(wallet?.available_balance || 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}
                    </h2>

                    {!isLady ? (
                        <div className="wallet-actions">
                            <form onSubmit={handleFunding} className="funding-form">
                                <label className="form-label">Min ₦2,000</label>
                                <div className="input-group">
                                    <input
                                        type="number"
                                        placeholder="Amount"
                                        value={fundingAmount}
                                        onChange={(e) => setFundingAmount(e.target.value)}
                                        min="2000"
                                        className="funding-input"
                                        disabled={isProcessing}
                                    />
                                    <button
                                        type="submit"
                                        className="btn btn-primary btn-fund"
                                        disabled={isProcessing}
                                    >
                                        {isProcessing ? '...' : 'Add Funds'}
                                    </button>
                                </div>
                            </form>
                        </div>
                    ) : (
                        <div className="wallet-actions">
                            <form onSubmit={handleWithdrawal} className="funding-form">
                                <label className="form-label">Min ₦15,000</label>
                                <div className="input-group">
                                    <input
                                        type="number"
                                        placeholder="Amount"
                                        value={withdrawalAmount}
                                        onChange={(e) => setWithdrawalAmount(e.target.value)}
                                        className="funding-input"
                                        disabled={isProcessing}
                                    />
                                    <button
                                        type="submit"
                                        className="btn btn-primary btn-fund"
                                        disabled={isProcessing}
                                    >
                                        {isProcessing ? '...' : 'Withdraw'}
                                    </button>
                                </div>
                            </form>
                        </div>
                    )}
                </div>

                <div className="stats-card-grid">
                    <div className="mini-stat-card">
                        <span className="mini-label">Pending</span>
                        <span className="mini-value">₦{parseFloat(wallet?.pending_balance || 0).toLocaleString()}</span>
                    </div>
                    <div className="mini-stat-card">
                        <span className="mini-label">Total Earned</span>
                        <span className="mini-value">₦{parseFloat(wallet?.total_earned || 0).toLocaleString()}</span>
                    </div>
                </div>

                {/* Gift Stats Section */}
                <div className="gift-stats-container">
                    <h3>🎁 Gift Earnings</h3>
                    <div className="gift-stats-grid">
                        <div className="gift-stat">
                            <span className="stat-val">
                                {transactions.filter(t => t.type === 'gift_received').length}
                            </span>
                            <span className="stat-lbl">Gifts Received</span>
                        </div>
                        <div className="gift-stat">
                            <span className="stat-val">
                                ₦{transactions
                                    .filter(t => t.type === 'gift_received')
                                    .reduce((acc, curr) => acc + parseFloat(curr.amount), 0)
                                    .toLocaleString()}
                            </span>
                            <span className="stat-lbl">From Gifts</span>
                        </div>
                    </div>
                </div>
            </div>

            <section className="payout-section">
                <h2 className="section-title">Payout Information</h2>
                <p className="section-subtitle">Where should we send your earnings?</p>

                <div className="payout-method-selector">
                    <button
                        type="button"
                        className={`method-btn ${payoutDetails.preferred_method === 'bank' ? 'active' : ''}`}
                        onClick={() => setPayoutDetails({ ...payoutDetails, preferred_method: 'bank' })}
                    >
                        🏦 Bank Account
                    </button>
                    <button
                        type="button"
                        className={`method-btn ${payoutDetails.preferred_method === 'paypal' ? 'active' : ''}`}
                        onClick={() => setPayoutDetails({ ...payoutDetails, preferred_method: 'paypal' })}
                    >
                        🅿️ PayPal
                    </button>
                </div>

                <form onSubmit={handleSavePayout} className="payout-form">
                    {payoutDetails.preferred_method === 'bank' ? (
                        <div className="payout-info-grid">
                            <div className="payout-form-group">
                                <label>Bank Name</label>
                                <input
                                    type="text"
                                    className="payout-input"
                                    placeholder="e.g. GTBank"
                                    value={payoutDetails.bank_name || ''}
                                    onChange={(e) => setPayoutDetails({ ...payoutDetails, bank_name: e.target.value })}
                                />
                            </div>
                            <div className="payout-form-group">
                                <label>Account Number</label>
                                <input
                                    type="text"
                                    className="payout-input"
                                    placeholder="0123456789"
                                    value={payoutDetails.account_number || ''}
                                    onChange={(e) => setPayoutDetails({ ...payoutDetails, account_number: e.target.value })}
                                />
                            </div>
                            <div className="payout-form-group" style={{ gridColumn: 'span 2' }}>
                                <label>Account Name</label>
                                <input
                                    type="text"
                                    className="payout-input"
                                    placeholder="Full name as seen on account"
                                    value={payoutDetails.account_name || ''}
                                    onChange={(e) => setPayoutDetails({ ...payoutDetails, account_name: e.target.value })}
                                />
                            </div>
                        </div>
                    ) : (
                        <div className="payout-form-group">
                            <label>PayPal Email</label>
                            <input
                                type="email"
                                className="payout-input"
                                placeholder="your@paypal.com"
                                value={payoutDetails.paypal_email || ''}
                                onChange={(e) => setPayoutDetails({ ...payoutDetails, paypal_email: e.target.value })}
                            />
                        </div>
                    )}

                    <button
                        type="submit"
                        className="btn btn-primary btn-save-payout"
                        disabled={isProcessing}
                    >
                        {isProcessing ? 'Saving...' : 'Save Payout Details'}
                    </button>
                </form>
            </section>

            <section className="transaction-history">
                <h2 className="section-title">Recent Activity</h2>
                {transactions.length > 0 ? (
                    <div className="transaction-list">
                        {transactions.map(tx => (
                            <div key={tx.id} className="transaction-item">
                                <div className={`tx-icon icon-${tx.type}`}>
                                    {tx.type === 'deposit' ? '💰' : tx.type === 'swipe_reward' ? '⭐' : tx.type === 'swipe_purchase' ? '💸' : '🎁'}
                                </div>
                                <div className="tx-info">
                                    <span className="tx-type">{tx.type.replace('_', ' ').charAt(0).toUpperCase() + tx.type.replace('_', ' ').slice(1)}</span>
                                    <span className="tx-description">{tx.description}</span>
                                    <span className="tx-date">{new Date(tx.created_at).toLocaleDateString()}</span>
                                </div>
                                <div className="tx-amount-status">
                                    <span className={`tx-amount mont-${tx.type}`}>
                                        {tx.type === 'withdrawal' || tx.type === 'swipe_purchase' ? '-' : '+'}
                                        ₦{parseFloat(tx.amount).toLocaleString()}
                                    </span>
                                    <span className={`tx-status status-${tx.status}`}>
                                        {tx.status}
                                    </span>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <div className="no-transactions">
                        <div className="empty-icon">💸</div>
                        <p>No transactions yet.</p>
                    </div>
                )}
            </section>
        </div >
    );
}

import { supabase } from '../lib/supabase';

// Helper for timeout
const withTimeout = (promise, ms = 10000) => {
    return Promise.race([
        promise,
        new Promise((_, reject) => setTimeout(() => reject(new Error('Request timed out')), ms))
    ]);
};

/**
 * Get a user's profile by ID.
 */
export async function getProfile(userId) {
    try {
        const { data, error } = await withTimeout(
            supabase
                .from('profiles')
                .select('*')
                .eq('id', userId)
                .single()
        );

        if (error) throw error;
        return { data, error: null };
    } catch (err) {
        console.error('getProfile error:', err.message);
        return { data: null, error: err.message };
    }
}

/**
 * Create a new profile.
 */
export async function createProfile(userId, profileData) {
    try {
        const { data, error } = await withTimeout(
            supabase
                .from('profiles')
                .insert({ id: userId, ...profileData })
                .select()
                .single()
        );

        if (error) throw error;
        return { data, error: null };
    } catch (err) {
        console.error('createProfile error:', err.message);
        return { data: null, error: err.message };
    }
}

/**
 * Update an existing profile.
 */
export async function updateProfile(userId, updates) {
    try {
        const { data, error } = await withTimeout(
            supabase
                .from('profiles')
                .update(updates)
                .eq('id', userId)
                .select()
                .single()
        );

        if (error) throw error;
        return { data, error: null };
    } catch (err) {
        console.error('updateProfile error:', err.message);
        return { data: null, error: err.message };
    }
}

/**
 * Upsert a profile (create or update).
 */
/**
 * Upsert a profile using Server-Side RPC (Robust).
 * Bypasses client-side RLS locks by running as security definer.
 */
export async function upsertProfile(userId, profileData) {
    try {
        console.log('Calling RPC update_profile_data for:', userId);

        const { data, error } = await withTimeout(
            supabase.rpc('update_profile_data', {
                p_full_name: profileData.full_name,
                p_age: profileData.age,
                p_gender: profileData.gender,
                p_university: profileData.university,
                p_bio: profileData.bio,
                p_avatar_url: profileData.avatar_url,
                p_email: profileData.email
            })
            , 30000); // 30s timeout

        if (error) {
            console.error('RPC failed:', error);
            // Fallback to old method just in case user didn't run SQL
            if (error.code === '42883') { // Function not found
                console.warn('RPC function not found, falling back to client-side upsert...');
                return clientSideUpsertFallback(userId, profileData);
            }
            throw error;
        }

        // Check the logical result from the RPC function
        if (data && data.success === false) {
            throw new Error(data.error || 'RPC reported failure');
        }

        return { data, error: null };
    } catch (err) {
        console.error('upsertProfile RPC error:', err.message);

        // Fallback to client-side for ANY error (Database constraint, Timeout, Function missing, etc.)
        console.warn('RPC failed or timed out, attempting client-side fallback...');
        console.log('Fallback data check (email):', profileData?.email ? 'Present' : 'MISSING');

        return clientSideUpsertFallback(userId, profileData);
    }
}

async function clientSideUpsertFallback(userId, profileData) {
    // ... (The previous Update/Insert logic as fallback)
    try {
        const safeData = { ...profileData, updated_at: new Date().toISOString() };
        // Attempt update first
        const { data: updateData, error: updateError } = await withTimeout(
            supabase.from('profiles').update(safeData).eq('id', userId).select().single()
            , 30000);

        if (!updateError && updateData) {
            console.log('Fallback: Update successful');
            return { data: updateData, error: null };
        }

        // If update failed or no row found, attempt insert
        console.warn('Fallback: Update failed, trying INSERT...', updateError?.message);
        const { data: insertData, error: insertError } = await withTimeout(
            supabase.from('profiles').insert({ id: userId, ...safeData }).select().single()
            , 30000);

        if (insertError) throw insertError;

        console.log('Fallback: Insert successful');
        return { data: insertData, error: null };
    } catch (e) {
        console.error('clientSideUpsertFallback error:', e.message);
        return { data: null, error: e.message };
    }
}

/**
 * Upload an avatar image.
 */
export async function uploadAvatar(file, userId) {
    try {
        const fileExt = file.name.split('.').pop();
        const fileName = `${userId}/${Date.now()}_avatar.${fileExt}`;
        const filePath = `${fileName}`;

        // 0. Check if bucket exists (connectivity check)
        const { error: bucketError } = await withTimeout(
            supabase.storage.getBucket('avatars'),
            5000
        );
        if (bucketError) {
            console.warn('Bucket check failed (might be RLS or connection):', bucketError.message);
        }

        // 1. Upload to 'avatars' bucket
        console.log(`Uploading to avatars: ${filePath}`);

        const { data, error: uploadError } = await withTimeout(
            supabase.storage
                .from('avatars')
                .upload(filePath, file, {
                    code: 'upsert',
                    upsert: true
                })
            , 60000); // Increased to 60s for slow connections

        if (uploadError) {
            console.error('Supabase Storage Upload Error:', uploadError);
            throw uploadError;
        }

        console.log('Upload success:', data);

        // 2. Get Public URL
        const { data: publicUrlData } = supabase.storage
            .from('avatars')
            .getPublicUrl(filePath);

        return { url: publicUrlData.publicUrl, error: null };
    } catch (err) {
        console.error('uploadAvatar error:', err.message);
        return { url: null, error: err.message };
    }
}

/**
 * Upload a voice intro.
 */
export async function uploadVoiceIntro(blob, userId) {
    try {
        const fileName = `${userId}/${Date.now()}_intro.webm`;
        const filePath = `${fileName}`;

        // 0. Check Bucket
        const { error: bucketError } = await withTimeout(
            supabase.storage.getBucket('voice-intros'),
            5000
        );
        if (bucketError) console.warn('Bucket check warning:', bucketError.message);

        // 1. Upload
        const { data, error: uploadError } = await withTimeout(
            supabase.storage
                .from('voice-intros')
                .upload(filePath, blob, {
                    contentType: 'audio/webm',
                    upsert: true
                })
            , 60000);

        if (uploadError) throw uploadError;

        // 2. Get URL
        const { data: publicUrlData } = supabase.storage
            .from('voice-intros')
            .getPublicUrl(filePath);

        return { url: publicUrlData.publicUrl, error: null };
    } catch (err) {
        console.error('uploadVoiceIntro error:', err.message);
